    fn window_anchor_picker(ui: &mut egui::Ui, preset: &mut WindowPreset) -> bool {
        let mut changed = false;
        let rows = [
            [
                WindowAnchor::TopLeft,
                WindowAnchor::Top,
                WindowAnchor::TopRight,
            ],
            [
                WindowAnchor::Left,
                WindowAnchor::Center,
                WindowAnchor::Right,
            ],
            [
                WindowAnchor::BottomLeft,
                WindowAnchor::Bottom,
                WindowAnchor::BottomRight,
            ],
        ];

        let mut draw_anchor_btn = |ui: &mut egui::Ui, anchor: WindowAnchor, selected: bool, hover_text: &str| -> egui::Response {
            let (rect, response) = ui.allocate_exact_size(egui::vec2(24.0, 24.0), egui::Sense::click());
            let visuals = ui.style().interact(&response);
            
            let bg_fill = if selected {
                ui.visuals().selection.bg_fill
            } else if response.hovered() {
                visuals.bg_fill
            } else {
                egui::Color32::from_rgb(54, 54, 54)
            };
            
            let rounding = egui::Rounding::same(6);
            ui.painter().rect_filled(rect, rounding, bg_fill);
            
            if selected {
                ui.painter().rect_stroke(
                    rect,
                    rounding,
                    egui::Stroke::new(1.0, ui.visuals().selection.stroke.color),
                    egui::StrokeKind::Inside,
                );
            }

            let fg_color = if selected {
                ui.visuals().selection.stroke.color
            } else {
                egui::Color32::from_rgb(220, 220, 220)
            };

            let center = rect.center();

            match anchor {
                WindowAnchor::Manual => {
                    ui.painter().text(
                        center + egui::vec2(0.0, -0.5),
                        egui::Align2::CENTER_CENTER,
                        "XY",
                        egui::FontId::proportional(11.0),
                        fg_color,
                    );
                }
                WindowAnchor::Center => {
                    ui.painter().circle_filled(center, 2.0, fg_color);
                    ui.painter().circle_stroke(
                        center,
                        5.0,
                        egui::Stroke::new(1.5, fg_color),
                    );
                    ui.painter().circle_stroke(
                        center,
                        8.0,
                        egui::Stroke::new(1.5, fg_color),
                    );
                }
                _ => {
                    let angle = match anchor {
                        WindowAnchor::TopLeft => 5.0 * std::f32::consts::PI / 4.0,
                        WindowAnchor::Top => 3.0 * std::f32::consts::PI / 2.0,
                        WindowAnchor::TopRight => 7.0 * std::f32::consts::PI / 4.0,
                        WindowAnchor::Left => std::f32::consts::PI,
                        WindowAnchor::Right => 0.0,
                        WindowAnchor::BottomLeft => 3.0 * std::f32::consts::PI / 4.0,
                        WindowAnchor::Bottom => std::f32::consts::PI / 2.0,
                        WindowAnchor::BottomRight => std::f32::consts::PI / 4.0,
                        _ => 0.0,
                    };

                    let dir = egui::vec2(angle.cos(), angle.sin());
                    let dir_perp = egui::vec2(-dir.y, dir.x);

                    let shaft_start = center - dir * 5.0;
                    let shaft_end = center + dir * 1.5;
                    ui.painter().line_segment(
                        [shaft_start, shaft_end],
                        egui::Stroke::new(2.8, fg_color),
                    );

                    let tip = center + dir * 6.5;
                    let left_wing = center + dir * 1.0 + dir_perp * 3.8;
                    let right_wing = center + dir * 1.0 - dir_perp * 3.8;
                    
                    ui.painter().add(egui::Shape::convex_polygon(
                        vec![tip, left_wing, right_wing],
                        fg_color,
                        egui::Stroke::NONE,
                    ));
                }
            }

            if !hover_text.is_empty() {
                response.on_hover_text(hover_text)
            } else {
                response
            }
        };

        ui.vertical(|ui| {
            ui.horizontal(|ui| {
                ui.vertical(|ui| {
                    let manual_response = draw_anchor_btn(
                        ui,
                        WindowAnchor::Manual,
                        preset.anchor == WindowAnchor::Manual,
                        "Manual X/Y position",
                    );
                    if manual_response.clicked() {
                        preset.anchor = WindowAnchor::Manual;
                        changed = true;
                    }
                });

                ui.add_space(10.0);

                ui.vertical(|ui| {
                    ui.spacing_mut().item_spacing = egui::vec2(4.0, 4.0);
                    for row in rows {
                        ui.horizontal(|ui| {
                            ui.spacing_mut().item_spacing = egui::vec2(4.0, 4.0);
                            for anchor in row {
                                let selected = preset.anchor == anchor;
                                let response = draw_anchor_btn(
                                    ui,
                                    anchor,
                                    selected,
                                    Self::window_anchor_label(anchor),
                                );
                                if response.clicked() {
                                    preset.anchor = anchor;
                                    changed = true;
                                }
                            }
                        });
                    }
                });
            });
        });

        changed
    }

    fn window_anchor_summary(anchor: WindowAnchor) -> &'static str {
        match anchor {
            WindowAnchor::Manual => "Manual X/Y",
            WindowAnchor::Center => "Auto: Center",
            WindowAnchor::TopLeft => "Auto: Top Left",
            WindowAnchor::Top => "Auto: Top Edge",
            WindowAnchor::TopRight => "Auto: Top Right",
            WindowAnchor::Left => "Auto: Left Edge",
            WindowAnchor::Right => "Auto: Right Edge",
            WindowAnchor::BottomLeft => "Auto: Bottom Left",
            WindowAnchor::Bottom => "Auto: Bottom Edge",
            WindowAnchor::BottomRight => "Auto: Bottom Right",
        }
    }

    fn window_anchor_preview_position(preset: &WindowPreset) -> Option<(i32, i32)> {
        if preset.anchor == WindowAnchor::Manual {
            return None;
        }

        #[cfg(windows)]
        unsafe {
            let screen_width = GetSystemMetrics(SM_CXSCREEN);
            let screen_height = GetSystemMetrics(SM_CYSCREEN);
            let width = preset.width.max(1);
            let height = preset.height.max(1);
            let position = match preset.anchor {
                WindowAnchor::Manual => (preset.x, preset.y),
                WindowAnchor::Center => ((screen_width - width) / 2, (screen_height - height) / 2),
                WindowAnchor::TopLeft => (0, 0),
                WindowAnchor::Top => (((screen_width - width) / 2), 0),
                WindowAnchor::TopRight => ((screen_width - width), 0),
                WindowAnchor::Left => (0, ((screen_height - height) / 2)),
                WindowAnchor::Right => ((screen_width - width), ((screen_height - height) / 2)),
                WindowAnchor::BottomLeft => (0, (screen_height - height)),
                WindowAnchor::Bottom => (((screen_width - width) / 2), (screen_height - height)),
                WindowAnchor::BottomRight => ((screen_width - width), (screen_height - height)),
            };
            return Some(position);
        }

        #[allow(unreachable_code)]
        None
    }

    fn render_zoom_rect_editor(
        ui: &mut egui::Ui,
        id_source: impl std::hash::Hash + Copy,
        label: &str,
        x: &mut i32,
        y: &mut i32,
        width: &mut i32,
        height: &mut i32,
        screen_size: egui::Vec2,
        preview: Option<&ZoomPreviewView>,
        target_preview_source: Option<(i32, i32, i32, i32)>,
        keep_aspect_ratio: Option<f32>,
    ) -> bool {
        let mut changed = false;
        ui.label(RichText::new(label).strong());
        let desired = vec2(ui.available_width().max(420.0), 260.0);
        let (canvas_rect, response) = ui.allocate_exact_size(desired, Sense::drag());
        let draw_rect = canvas_rect.shrink(8.0);
        let scale = (draw_rect.width() / screen_size.x)
            .min(draw_rect.height() / screen_size.y)
            .max(0.0001);
        let preview_size = vec2(screen_size.x * scale, screen_size.y * scale);
        let preview_rect = egui::Rect::from_center_size(draw_rect.center(), preview_size);
        ui.painter().rect_filled(
            preview_rect,
            8.0,
            Color32::from_rgba_premultiplied(24, 36, 30, 220),
        );
        ui.painter().rect_stroke(
            preview_rect,
            8.0,
            egui::Stroke::new(1.0, Color32::from_rgb(112, 156, 128)),
            egui::StrokeKind::Outside,
        );

        let selection_bounds_rect = preview_rect;
        let (coord_width, coord_height, content_scale, preview_content_rect) =
            if let Some(preview_frame) = preview {
                let window_pos = egui::pos2(
                    selection_bounds_rect.left() + (preview_frame.screen_x as f32 * scale),
                    selection_bounds_rect.top() + (preview_frame.screen_y as f32 * scale),
                );
                let window_size = vec2(
                    preview_frame.logical_width.max(1) as f32 * scale,
                    preview_frame.logical_height.max(1) as f32 * scale,
                );
                (
                    screen_size.x,
                    screen_size.y,
                    scale,
                    egui::Rect::from_min_size(window_pos, window_size),
                )
            } else {
                (screen_size.x, screen_size.y, scale, selection_bounds_rect)
            };

        if let Some(preview_frame) = preview {
            ui.painter().image(
                preview_frame.texture.id(),
                preview_content_rect,
                egui::Rect::from_min_max(egui::pos2(0.0, 0.0), egui::pos2(1.0, 1.0)),
                Color32::WHITE,
            );
            ui.painter().text(
                preview_content_rect.left_top() + vec2(8.0, 8.0),
                egui::Align2::LEFT_TOP,
                &preview_frame.title,
                egui::TextStyle::Small.resolve(ui.style()),
                Color32::WHITE,
            );
        }

        let min_size = vec2(6.0, 6.0);
        let mut rect = egui::Rect::from_min_size(
            egui::pos2(
                selection_bounds_rect.left() + (*x as f32 * content_scale),
                selection_bounds_rect.top() + (*y as f32 * content_scale),
            ),
            vec2(
                (*width).max(1) as f32 * content_scale,
                (*height).max(1) as f32 * content_scale,
            ),
        );
        rect = rect.intersect(selection_bounds_rect);
        if rect.width() < min_size.x {
            rect.max.x = (rect.min.x + min_size.x).min(selection_bounds_rect.right());
        }
        if rect.height() < min_size.y {
            rect.max.y = (rect.min.y + min_size.y).min(selection_bounds_rect.bottom());
        }

        #[derive(Clone, Copy, Debug, PartialEq, Eq)]
        enum SelectionDragHandle {
            None,
            Center,
            TopLeft,
            TopRight,
            BottomLeft,
            BottomRight,
            Left,
            Right,
            Top,
            Bottom,
        }

        let drag_id = ui.make_persistent_id((id_source, "zoom-selection-drag-handle"));
        let mut active_handle: SelectionDragHandle = ui.data_mut(|d| d.get_temp(drag_id).unwrap_or(SelectionDragHandle::None));

        if response.drag_started() {
            if let Some(pointer_pos) = response.interact_pointer_pos() {
                let dist_tl = pointer_pos.distance(rect.left_top());
                let dist_tr = pointer_pos.distance(rect.right_top());
                let dist_bl = pointer_pos.distance(rect.left_bottom());
                let dist_br = pointer_pos.distance(rect.right_bottom());
                
                active_handle = if dist_tl < 14.0 {
                    SelectionDragHandle::TopLeft
                } else if dist_tr < 14.0 {
                    SelectionDragHandle::TopRight
                } else if dist_bl < 14.0 {
                    SelectionDragHandle::BottomLeft
                } else if dist_br < 14.0 {
                    SelectionDragHandle::BottomRight
                } else if (pointer_pos.x - rect.left()).abs() < 10.0 && pointer_pos.y >= rect.top() && pointer_pos.y <= rect.bottom() {
                    SelectionDragHandle::Left
                } else if (pointer_pos.x - rect.right()).abs() < 10.0 && pointer_pos.y >= rect.top() && pointer_pos.y <= rect.bottom() {
                    SelectionDragHandle::Right
                } else if (pointer_pos.y - rect.top()).abs() < 10.0 && pointer_pos.x >= rect.left() && pointer_pos.x <= rect.right() {
                    SelectionDragHandle::Top
                } else if (pointer_pos.y - rect.bottom()).abs() < 10.0 && pointer_pos.x >= rect.left() && pointer_pos.x <= rect.right() {
                    SelectionDragHandle::Bottom
                } else if rect.contains(pointer_pos) {
                    SelectionDragHandle::Center
                } else {
                    SelectionDragHandle::None
                };
                ui.data_mut(|d| d.insert_temp(drag_id, active_handle));
            }
        }

        if response.dragged() && active_handle != SelectionDragHandle::None {
            let delta = response.drag_delta();
            let shift_pressed = ui.input(|i| i.modifiers.shift);
            let ctrl_pressed = ui.input(|i| i.modifiers.ctrl);
            let aspect = if rect.height() > 0.0 { rect.width() / rect.height() } else { 16.0 / 9.0 };
            let target_aspect = if let Some(preview_frame) = preview {
                if preview_frame.logical_height > 0 {
                    preview_frame.logical_width as f32 / preview_frame.logical_height as f32
                } else {
                    16.0 / 9.0
                }
            } else {
                if screen_size.y > 0.0 {
                    screen_size.x / screen_size.y
                } else {
                    16.0 / 9.0
                }
            };
            let lock_aspect = keep_aspect_ratio.unwrap_or(
                if ctrl_pressed {
                    target_aspect
                } else if shift_pressed {
                    aspect
                } else {
                    0.0
                }
            );

            changed = true;

            match active_handle {
                SelectionDragHandle::Center => {
                    rect = rect.translate(delta);
                }
                SelectionDragHandle::Right => {
                    let new_w = (rect.width() + delta.x).max(min_size.x);
                    if lock_aspect > 0.0 {
                        let new_h = new_w / lock_aspect;
                        rect.max.x = rect.min.x + new_w;
                        rect.max.y = rect.min.y + new_h;
                    } else {
                        rect.max.x = rect.min.x + new_w;
                    }
                }
                SelectionDragHandle::Left => {
                    let new_w = (rect.width() - delta.x).max(min_size.x);
                    if lock_aspect > 0.0 {
                        let new_h = new_w / lock_aspect;
                        rect.min.x = rect.max.x - new_w;
                        rect.min.y = rect.max.y - new_h;
                    } else {
                        rect.min.x = rect.max.x - new_w;
                    }
                }
                SelectionDragHandle::Bottom => {
                    let new_h = (rect.height() + delta.y).max(min_size.y);
                    if lock_aspect > 0.0 {
                        let new_w = new_h * lock_aspect;
                        rect.max.x = rect.min.x + new_w;
                        rect.max.y = rect.min.y + new_h;
                    } else {
                        rect.max.y = rect.min.y + new_h;
                    }
                }
                SelectionDragHandle::Top => {
                    let new_h = (rect.height() - delta.y).max(min_size.y);
                    if lock_aspect > 0.0 {
                        let new_w = new_h * lock_aspect;
                        rect.min.x = rect.max.x - new_w;
                        rect.min.y = rect.max.y - new_h;
                    } else {
                        rect.min.y = rect.max.y - new_h;
                    }
                }
                SelectionDragHandle::BottomRight => {
                    let new_w = (rect.width() + delta.x).max(min_size.x);
                    if lock_aspect > 0.0 {
                        let new_h = new_w / lock_aspect;
                        rect.max.x = rect.min.x + new_w;
                        rect.max.y = rect.min.y + new_h;
                    } else {
                        let new_h = (rect.height() + delta.y).max(min_size.y);
                        rect.max.x = rect.min.x + new_w;
                        rect.max.y = rect.min.y + new_h;
                    }
                }
                SelectionDragHandle::TopLeft => {
                    let new_w = (rect.width() - delta.x).max(min_size.x);
                    if lock_aspect > 0.0 {
                        let new_h = new_w / lock_aspect;
                        rect.min.x = rect.max.x - new_w;
                        rect.min.y = rect.max.y - new_h;
                    } else {
                        let new_h = (rect.height() - delta.y).max(min_size.y);
                        rect.min.x = rect.max.x - new_w;
                        rect.min.y = rect.max.y - new_h;
                    }
                }
                SelectionDragHandle::TopRight => {
                    let new_w = (rect.width() + delta.x).max(min_size.x);
                    if lock_aspect > 0.0 {
                        let new_h = new_w / lock_aspect;
                        rect.max.x = rect.min.x + new_w;
                        rect.min.y = rect.max.y - new_h;
                    } else {
                        let new_h = (rect.height() - delta.y).max(min_size.y);
                        rect.max.x = rect.min.x + new_w;
                        rect.min.y = rect.max.y - new_h;
                    }
                }
                SelectionDragHandle::BottomLeft => {
                    let new_w = (rect.width() - delta.x).max(min_size.x);
                    if lock_aspect > 0.0 {
                        let new_h = new_w / lock_aspect;
                        rect.min.x = rect.max.x - new_w;
                        rect.max.y = rect.min.y + new_h;
                    } else {
                        let new_h = (rect.height() + delta.y).max(min_size.y);
                        rect.min.x = rect.max.x - new_w;
                        rect.max.y = rect.min.y + new_h;
                    }
                }
                SelectionDragHandle::None => {}
            }

            // Bound checking
            if rect.left() < selection_bounds_rect.left() {
                rect = rect.translate(vec2(selection_bounds_rect.left() - rect.left(), 0.0));
            }
            if rect.top() < selection_bounds_rect.top() {
                rect = rect.translate(vec2(0.0, selection_bounds_rect.top() - rect.top()));
            }
            if rect.right() > selection_bounds_rect.right() {
                rect = rect.translate(vec2(selection_bounds_rect.right() - rect.right(), 0.0));
            }
            if rect.bottom() > selection_bounds_rect.bottom() {
                rect = rect.translate(vec2(0.0, selection_bounds_rect.bottom() - rect.bottom()));
            }

            rect.min.x = rect.min.x.clamp(
                selection_bounds_rect.left(),
                selection_bounds_rect.right() - min_size.x,
            );
            rect.min.y = rect.min.y.clamp(
                selection_bounds_rect.top(),
                selection_bounds_rect.bottom() - min_size.y,
            );
            rect.max.x = rect
                .max
                .x
                .clamp(rect.min.x + min_size.x, selection_bounds_rect.right());
            rect.max.y = rect
                .max
                .y
                .clamp(rect.min.y + min_size.y, selection_bounds_rect.bottom());
        }

        if ui.input(|i| i.pointer.any_released()) {
            active_handle = SelectionDragHandle::None;
            ui.data_mut(|d| d.insert_temp(drag_id, active_handle));
        }

        if response.hovered() || active_handle != SelectionDragHandle::None {
            if let Some(pointer_pos) = ui.input(|i| i.pointer.hover_pos()) {
                let dist_tl = pointer_pos.distance(rect.left_top());
                let dist_tr = pointer_pos.distance(rect.right_top());
                let dist_bl = pointer_pos.distance(rect.left_bottom());
                let dist_br = pointer_pos.distance(rect.right_bottom());

                let handle_to_use = if active_handle != SelectionDragHandle::None {
                    active_handle
                } else if dist_tl < 14.0 {
                    SelectionDragHandle::TopLeft
                } else if dist_tr < 14.0 {
                    SelectionDragHandle::TopRight
                } else if dist_bl < 14.0 {
                    SelectionDragHandle::BottomLeft
                } else if dist_br < 14.0 {
                    SelectionDragHandle::BottomRight
                } else if (pointer_pos.x - rect.left()).abs() < 10.0 && pointer_pos.y >= rect.top() && pointer_pos.y <= rect.bottom() {
                    SelectionDragHandle::Left
                } else if (pointer_pos.x - rect.right()).abs() < 10.0 && pointer_pos.y >= rect.top() && pointer_pos.y <= rect.bottom() {
                    SelectionDragHandle::Right
                } else if (pointer_pos.y - rect.top()).abs() < 10.0 && pointer_pos.x >= rect.left() && pointer_pos.x <= rect.right() {
                    SelectionDragHandle::Top
                } else if (pointer_pos.y - rect.bottom()).abs() < 10.0 && pointer_pos.x >= rect.left() && pointer_pos.x <= rect.right() {
                    SelectionDragHandle::Bottom
                } else if rect.contains(pointer_pos) {
                    SelectionDragHandle::Center
                } else {
                    SelectionDragHandle::None
                };

                match handle_to_use {
                    SelectionDragHandle::TopLeft | SelectionDragHandle::BottomRight => {
                        ui.ctx().set_cursor_icon(egui::CursorIcon::ResizeNwSe);
                    }
                    SelectionDragHandle::TopRight | SelectionDragHandle::BottomLeft => {
                        ui.ctx().set_cursor_icon(egui::CursorIcon::ResizeNeSw);
                    }
                    SelectionDragHandle::Left | SelectionDragHandle::Right => {
                        ui.ctx().set_cursor_icon(egui::CursorIcon::ResizeHorizontal);
                    }
                    SelectionDragHandle::Top | SelectionDragHandle::Bottom => {
                        ui.ctx().set_cursor_icon(egui::CursorIcon::ResizeVertical);
                    }
                    SelectionDragHandle::Center => {
                        if active_handle == SelectionDragHandle::Center {
                            ui.ctx().set_cursor_icon(egui::CursorIcon::Grabbing);
                        } else {
                            ui.ctx().set_cursor_icon(egui::CursorIcon::Grab);
                        }
                    }
                    _ => {}
                }
            }
        }

        if let (Some(preview_frame), Some((src_x, src_y, src_w, src_h))) =
            (preview, target_preview_source)
        {
            let uv = egui::Rect::from_min_max(
                egui::pos2(
                    (src_x as f32 / preview_frame.logical_width.max(1) as f32).clamp(0.0, 1.0),
                    (src_y as f32 / preview_frame.logical_height.max(1) as f32).clamp(0.0, 1.0),
                ),
                egui::pos2(
                    ((src_x + src_w) as f32 / preview_frame.logical_width.max(1) as f32)
                        .clamp(0.0, 1.0),
                    ((src_y + src_h) as f32 / preview_frame.logical_height.max(1) as f32)
                        .clamp(0.0, 1.0),
                ),
            );
            if uv.width() > 0.0 && uv.height() > 0.0 {
                ui.painter()
                    .image(preview_frame.texture.id(), rect, uv, Color32::WHITE);
            }
        }

        ui.painter().rect_stroke(
            rect,
            6.0,
            egui::Stroke::new(2.0, Color32::from_rgb(124, 240, 164)),
            egui::StrokeKind::Outside,
        );

        let size_text = format!("{}x{}", *width, *height);
        ui.painter().text(
            rect.left_top() + egui::vec2(4.0, 4.0),
            egui::Align2::LEFT_TOP,
            size_text,
            egui::FontId::proportional(10.0),
            Color32::from_rgb(124, 240, 164),
        );

        if changed {
            *x = ((rect.left() - selection_bounds_rect.left()) / content_scale).round() as i32;
            *y = ((rect.top() - selection_bounds_rect.top()) / content_scale).round() as i32;
            *width = (rect.width() / content_scale).round().max(1.0) as i32;
            *height = (rect.height() / content_scale).round().max(1.0) as i32;
            *x = (*x).clamp(0, coord_width.round() as i32);
            *y = (*y).clamp(0, coord_height.round() as i32);
        }

        ui.label(RichText::new(format!("X={} Y={} W={} H={}", *x, *y, *width, *height)).small());
        changed
    }

    fn edit_rgba_color(ui: &mut egui::Ui, color: &mut RgbaColor) -> egui::Response {
        let mut rgba = [color.r, color.g, color.b, color.a];
        let response = ui.color_edit_button_srgba_unmultiplied(&mut rgba);
        if response.changed() {
            color.r = rgba[0];
            color.g = rgba[1];
            color.b = rgba[2];
            color.a = rgba[3];
        }
        response
    }

    fn render_hud_rect_editor(
        ui: &mut egui::Ui,
        id_source: impl std::hash::Hash + Copy,
        preset: &mut HudPreset,
    ) -> bool {
        let mut changed = false;
        let screen_size = Self::screen_size();
        let desired = vec2(ui.available_width().max(560.0), 420.0);
        let (canvas_rect, response) = ui.allocate_exact_size(desired, Sense::drag());
        let draw_rect = canvas_rect.shrink(8.0);
        let scale = (draw_rect.width() / screen_size.x)
            .min(draw_rect.height() / screen_size.y)
            .max(0.0001);
        let preview_size = vec2(screen_size.x * scale, screen_size.y * scale);
        let preview_rect = egui::Rect::from_center_size(draw_rect.center(), preview_size);
        ui.painter().rect_filled(
            preview_rect,
            8.0,
            Color32::from_rgba_premultiplied(18, 24, 22, 220),
        );
        ui.painter().rect_stroke(
            preview_rect,
            8.0,
            egui::Stroke::new(1.0, Color32::from_rgb(104, 148, 124)),
            egui::StrokeKind::Outside,
        );

        let min_size = vec2(4.0, 4.0);
        let mut rect = egui::Rect::from_min_size(
            egui::pos2(
                preview_rect.left() + (preset.x as f32 * scale),
                preview_rect.top() + (preset.y as f32 * scale),
            ),
            vec2(
                preset.width.max(1) as f32 * scale,
                preset.height.max(1) as f32 * scale,
            ),
        )
        .intersect(preview_rect);
        if rect.width() < min_size.x {
            rect.max.x = (rect.min.x + min_size.x).min(preview_rect.right());
        }
        if rect.height() < min_size.y {
            rect.max.y = (rect.min.y + min_size.y).min(preview_rect.bottom());
        }

        let rect_id = ui.make_persistent_id((id_source, "toolbox-rect"));
        let drag_id = ui.make_persistent_id((id_source, "hud-selection-drag-handle"));

        #[derive(Clone, Copy, Debug, PartialEq, Eq)]
        enum SelectionDragHandle {
            None,
            Center,
            TopLeft,
            TopRight,
            BottomLeft,
            BottomRight,
            Left,
            Right,
            Top,
            Bottom,
        }

        let mut active_handle: SelectionDragHandle = ui.data_mut(|d| d.get_temp(drag_id).unwrap_or(SelectionDragHandle::None));

        if response.drag_started() {
            if let Some(pointer_pos) = response.interact_pointer_pos() {
                let dist_tl = pointer_pos.distance(rect.left_top());
                let dist_tr = pointer_pos.distance(rect.right_top());
                let dist_bl = pointer_pos.distance(rect.left_bottom());
                let dist_br = pointer_pos.distance(rect.right_bottom());

                active_handle = if dist_tl < 14.0 {
                    SelectionDragHandle::TopLeft
                } else if dist_tr < 14.0 {
                    SelectionDragHandle::TopRight
                } else if dist_bl < 14.0 {
                    SelectionDragHandle::BottomLeft
                } else if dist_br < 14.0 {
                    SelectionDragHandle::BottomRight
                } else if (pointer_pos.x - rect.left()).abs() < 10.0 && pointer_pos.y >= rect.top() && pointer_pos.y <= rect.bottom() {
                    SelectionDragHandle::Left
                } else if (pointer_pos.x - rect.right()).abs() < 10.0 && pointer_pos.y >= rect.top() && pointer_pos.y <= rect.bottom() {
                    SelectionDragHandle::Right
                } else if (pointer_pos.y - rect.top()).abs() < 10.0 && pointer_pos.x >= rect.left() && pointer_pos.x <= rect.right() {
                    SelectionDragHandle::Top
                } else if (pointer_pos.y - rect.bottom()).abs() < 10.0 && pointer_pos.x >= rect.left() && pointer_pos.x <= rect.right() {
                    SelectionDragHandle::Bottom
                } else if rect.contains(pointer_pos) {
                    SelectionDragHandle::Center
                } else {
                    SelectionDragHandle::None
                };
                ui.data_mut(|d| d.insert_temp(drag_id, active_handle));
            }
        }

        if response.dragged() && active_handle != SelectionDragHandle::None {
            let delta = response.drag_delta();
            let shift_pressed = ui.input(|i| i.modifiers.shift);
            let original_aspect = if preset.height > 0 { preset.width as f32 / preset.height as f32 } else { 16.0 / 9.0 };
            let lock_aspect = if shift_pressed { original_aspect } else { 0.0 };

            changed = true;

            match active_handle {
                SelectionDragHandle::Center => {
                    rect = rect.translate(delta);
                }
                SelectionDragHandle::Right => {
                    let new_w = (rect.width() + delta.x).max(min_size.x);
                    if lock_aspect > 0.0 {
                        let new_h = new_w / lock_aspect;
                        rect.max.x = rect.min.x + new_w;
                        rect.max.y = rect.min.y + new_h;
                    } else {
                        rect.max.x = rect.min.x + new_w;
                    }
                }
                SelectionDragHandle::Left => {
                    let new_w = (rect.width() - delta.x).max(min_size.x);
                    if lock_aspect > 0.0 {
                        let new_h = new_w / lock_aspect;
                        rect.min.x = rect.max.x - new_w;
                        rect.min.y = rect.max.y - new_h;
                    } else {
                        rect.min.x = rect.max.x - new_w;
                    }
                }
                SelectionDragHandle::Bottom => {
                    let new_h = (rect.height() + delta.y).max(min_size.y);
                    if lock_aspect > 0.0 {
                        let new_w = new_h * lock_aspect;
                        rect.max.x = rect.min.x + new_w;
                        rect.max.y = rect.min.y + new_h;
                    } else {
                        rect.max.y = rect.min.y + new_h;
                    }
                }
                SelectionDragHandle::Top => {
                    let new_h = (rect.height() - delta.y).max(min_size.y);
                    if lock_aspect > 0.0 {
                        let new_w = new_h * lock_aspect;
                        rect.min.x = rect.max.x - new_w;
                        rect.min.y = rect.max.y - new_h;
                    } else {
                        rect.min.y = rect.max.y - new_h;
                    }
                }
                SelectionDragHandle::BottomRight => {
                    let new_w = (rect.width() + delta.x).max(min_size.x);
                    if lock_aspect > 0.0 {
                        let new_h = new_w / lock_aspect;
                        rect.max.x = rect.min.x + new_w;
                        rect.max.y = rect.min.y + new_h;
                    } else {
                        let new_h = (rect.height() + delta.y).max(min_size.y);
                        rect.max.x = rect.min.x + new_w;
                        rect.max.y = rect.min.y + new_h;
                    }
                }
                SelectionDragHandle::TopLeft => {
                    let new_w = (rect.width() - delta.x).max(min_size.x);
                    if lock_aspect > 0.0 {
                        let new_h = new_w / lock_aspect;
                        rect.min.x = rect.max.x - new_w;
                        rect.min.y = rect.max.y - new_h;
                    } else {
                        let new_h = (rect.height() - delta.y).max(min_size.y);
                        rect.min.x = rect.max.x - new_w;
                        rect.min.y = rect.max.y - new_h;
                    }
                }
                SelectionDragHandle::TopRight => {
                    let new_w = (rect.width() + delta.x).max(min_size.x);
                    if lock_aspect > 0.0 {
                        let new_h = new_w / lock_aspect;
                        rect.max.x = rect.min.x + new_w;
                        rect.min.y = rect.max.y - new_h;
                    } else {
                        let new_h = (rect.height() - delta.y).max(min_size.y);
                        rect.max.x = rect.min.x + new_w;
                        rect.min.y = rect.max.y - new_h;
                    }
                }
                SelectionDragHandle::BottomLeft => {
                    let new_w = (rect.width() - delta.x).max(min_size.x);
                    if lock_aspect > 0.0 {
                        let new_h = new_w / lock_aspect;
                        rect.min.x = rect.max.x - new_w;
                        rect.max.y = rect.min.y + new_h;
                    } else {
                        let new_h = (rect.height() + delta.y).max(min_size.y);
                        rect.min.x = rect.max.x - new_w;
                        rect.max.y = rect.min.y + new_h;
                    }
                }
                SelectionDragHandle::None => {}
            }

            if rect.left() < preview_rect.left() {
                rect = rect.translate(vec2(preview_rect.left() - rect.left(), 0.0));
            }
            if rect.top() < preview_rect.top() {
                rect = rect.translate(vec2(0.0, preview_rect.top() - rect.top()));
            }
            if rect.right() > preview_rect.right() {
                rect = rect.translate(vec2(preview_rect.right() - rect.right(), 0.0));
            }
            if rect.bottom() > preview_rect.bottom() {
                rect = rect.translate(vec2(0.0, preview_rect.bottom() - rect.bottom()));
            }

            rect.min.x = rect.min.x.clamp(
                preview_rect.left(),
                preview_rect.right() - min_size.x,
            );
            rect.min.y = rect.min.y.clamp(
                preview_rect.top(),
                preview_rect.bottom() - min_size.y,
            );
            rect.max.x = rect
                .max
                .x
                .clamp(rect.min.x + min_size.x, preview_rect.right());
            rect.max.y = rect
                .max
                .y
                .clamp(rect.min.y + min_size.y, preview_rect.bottom());
        }

        if ui.input(|i| i.pointer.any_released()) {
            active_handle = SelectionDragHandle::None;
            ui.data_mut(|d| d.insert_temp(drag_id, active_handle));
        }

        if response.hovered() || active_handle != SelectionDragHandle::None {
            if let Some(pointer_pos) = ui.input(|i| i.pointer.hover_pos()) {
                let dist_tl = pointer_pos.distance(rect.left_top());
                let dist_tr = pointer_pos.distance(rect.right_top());
                let dist_bl = pointer_pos.distance(rect.left_bottom());
                let dist_br = pointer_pos.distance(rect.right_bottom());

                let handle_to_use = if active_handle != SelectionDragHandle::None {
                    active_handle
                } else if dist_tl < 14.0 {
                    SelectionDragHandle::TopLeft
                } else if dist_tr < 14.0 {
                    SelectionDragHandle::TopRight
                } else if dist_bl < 14.0 {
                    SelectionDragHandle::BottomLeft
                } else if dist_br < 14.0 {
                    SelectionDragHandle::BottomRight
                } else if (pointer_pos.x - rect.left()).abs() < 10.0 && pointer_pos.y >= rect.top() && pointer_pos.y <= rect.bottom() {
                    SelectionDragHandle::Left
                } else if (pointer_pos.x - rect.right()).abs() < 10.0 && pointer_pos.y >= rect.top() && pointer_pos.y <= rect.bottom() {
                    SelectionDragHandle::Right
                } else if (pointer_pos.y - rect.top()).abs() < 10.0 && pointer_pos.x >= rect.left() && pointer_pos.x <= rect.right() {
                    SelectionDragHandle::Top
                } else if (pointer_pos.y - rect.bottom()).abs() < 10.0 && pointer_pos.x >= rect.left() && pointer_pos.x <= rect.right() {
                    SelectionDragHandle::Bottom
                } else if rect.contains(pointer_pos) {
                    SelectionDragHandle::Center
                } else {
                    SelectionDragHandle::None
                };

                match handle_to_use {
                    SelectionDragHandle::TopLeft | SelectionDragHandle::BottomRight => {
                        ui.ctx().set_cursor_icon(egui::CursorIcon::ResizeNwSe);
                    }
                    SelectionDragHandle::TopRight | SelectionDragHandle::BottomLeft => {
                        ui.ctx().set_cursor_icon(egui::CursorIcon::ResizeNeSw);
                    }
                    SelectionDragHandle::Left | SelectionDragHandle::Right => {
                        ui.ctx().set_cursor_icon(egui::CursorIcon::ResizeHorizontal);
                    }
                    SelectionDragHandle::Top | SelectionDragHandle::Bottom => {
                        ui.ctx().set_cursor_icon(egui::CursorIcon::ResizeVertical);
                    }
                    SelectionDragHandle::Center => {
                        if active_handle == SelectionDragHandle::Center {
                            ui.ctx().set_cursor_icon(egui::CursorIcon::Grabbing);
                        } else {
                            ui.ctx().set_cursor_icon(egui::CursorIcon::Grab);
                        }
                    }
                    _ => {}
                }
            }
        }

        let size_text = format!("{}x{}", preset.width, preset.height);
        ui.painter().text(
            rect.left_top() + egui::vec2(4.0, 4.0),
            egui::Align2::LEFT_TOP,
            size_text,
            egui::FontId::proportional(10.0),
            Color32::from_rgb(124, 240, 164),
        );

        let bg_alpha = (preset.background_opacity.clamp(0.0, 1.0) * 255.0).round() as u8;
        let background = Color32::from_rgba_premultiplied(
            ((preset.background_color.r as u32 * bg_alpha as u32) / 255) as u8,
            ((preset.background_color.g as u32 * bg_alpha as u32) / 255) as u8,
            ((preset.background_color.b as u32 * bg_alpha as u32) / 255) as u8,
            bg_alpha,
        );
        let text_color = Color32::from_rgba_premultiplied(
            preset.text_color.r,
            preset.text_color.g,
            preset.text_color.b,
            preset.text_color.a,
        );
        let rounding = if preset.rounded_background { 12.0 } else { 0.0 };
        if bg_alpha > 0 {
            ui.painter().rect_filled(rect, rounding, background);
        }
        ui.painter().rect_stroke(
            rect,
            rounding,
            egui::Stroke::new(2.0, Color32::from_rgb(124, 240, 164)),
            egui::StrokeKind::Outside,
        );
        ui.painter().text(
            rect.center(),
            egui::Align2::CENTER_CENTER,
            if preset.text.trim().is_empty() {
                "Toolbox preview"
            } else {
                preset.text.as_str()
            },
            egui::FontId::proportional((preset.font_size * scale).clamp(2.0, 200.0)),
            text_color,
        );

        if changed {
            preset.x = ((rect.left() - preview_rect.left()) / scale).round() as i32;
            preset.y = ((rect.top() - preview_rect.top()) / scale).round() as i32;
            preset.width = (rect.width() / scale).round().max(1.0) as i32;
            preset.height = (rect.height() / scale).round().max(1.0) as i32;
        }

        ui.label(
            RichText::new(format!(
                "X={} Y={} W={} H={}",
                preset.x, preset.y, preset.width, preset.height
            ))
            .small(),
        );
        changed
    }

    pub(crate) fn render_timer_rect_editor(
        ui: &mut egui::Ui,
        id_source: impl std::hash::Hash + Copy,
        preset: &mut TimerPreset,
    ) -> bool {
        let mut changed = false;
        let screen_size = Self::screen_size();
        let desired = vec2(ui.available_width().max(560.0), 420.0);
        let (canvas_rect, response) = ui.allocate_exact_size(desired, Sense::drag());
        let draw_rect = canvas_rect.shrink(8.0);
        let scale = (draw_rect.width() / screen_size.x)
            .min(draw_rect.height() / screen_size.y)
            .max(0.0001);
        let preview_size = vec2(screen_size.x * scale, screen_size.y * scale);
        let preview_rect = egui::Rect::from_center_size(draw_rect.center(), preview_size);
        ui.painter().rect_filled(
            preview_rect,
            8.0,
            Color32::from_rgba_premultiplied(18, 24, 22, 220),
        );
        ui.painter().rect_stroke(
            preview_rect,
            8.0,
            egui::Stroke::new(1.0, Color32::from_rgb(104, 148, 124)),
            egui::StrokeKind::Outside,
        );

        let min_size = vec2(4.0, 4.0);
        let mut rect = egui::Rect::from_min_size(
            egui::pos2(
                preview_rect.left() + (preset.x as f32 * scale),
                preview_rect.top() + (preset.y as f32 * scale),
            ),
            vec2(
                preset.width.max(1) as f32 * scale,
                preset.height.max(1) as f32 * scale,
            ),
        )
        .intersect(preview_rect);
        if rect.width() < min_size.x {
            rect.max.x = (rect.min.x + min_size.x).min(preview_rect.right());
        }
        if rect.height() < min_size.y {
            rect.max.y = (rect.min.y + min_size.y).min(preview_rect.bottom());
        }

        let rect_id = ui.make_persistent_id((id_source, "timer-rect"));
        let drag_id = ui.make_persistent_id((id_source, "timer-selection-drag-handle"));

        #[derive(Clone, Copy, Debug, PartialEq, Eq)]
        enum SelectionDragHandle {
            None,
            Center,
            TopLeft,
            TopRight,
            BottomLeft,
            BottomRight,
            Left,
            Right,
            Top,
            Bottom,
        }

        let mut active_handle: SelectionDragHandle = ui.data_mut(|d| d.get_temp(drag_id).unwrap_or(SelectionDragHandle::None));

        if response.drag_started() {
            if let Some(pointer_pos) = response.interact_pointer_pos() {
                let dist_tl = pointer_pos.distance(rect.left_top());
                let dist_tr = pointer_pos.distance(rect.right_top());
                let dist_bl = pointer_pos.distance(rect.left_bottom());
                let dist_br = pointer_pos.distance(rect.right_bottom());

                active_handle = if dist_tl < 14.0 {
                    SelectionDragHandle::TopLeft
                } else if dist_tr < 14.0 {
                    SelectionDragHandle::TopRight
                } else if dist_bl < 14.0 {
                    SelectionDragHandle::BottomLeft
                } else if dist_br < 14.0 {
                    SelectionDragHandle::BottomRight
                } else if (pointer_pos.x - rect.left()).abs() < 10.0 && pointer_pos.y >= rect.top() && pointer_pos.y <= rect.bottom() {
                    SelectionDragHandle::Left
                } else if (pointer_pos.x - rect.right()).abs() < 10.0 && pointer_pos.y >= rect.top() && pointer_pos.y <= rect.bottom() {
                    SelectionDragHandle::Right
                } else if (pointer_pos.y - rect.top()).abs() < 10.0 && pointer_pos.x >= rect.left() && pointer_pos.x <= rect.right() {
                    SelectionDragHandle::Top
                } else if (pointer_pos.y - rect.bottom()).abs() < 10.0 && pointer_pos.x >= rect.left() && pointer_pos.x <= rect.right() {
                    SelectionDragHandle::Bottom
                } else if rect.contains(pointer_pos) {
                    SelectionDragHandle::Center
                } else {
                    SelectionDragHandle::None
                };
                ui.data_mut(|d| d.insert_temp(drag_id, active_handle));
            }
        }

        if response.dragged() && active_handle != SelectionDragHandle::None {
            let delta = response.drag_delta();
            let shift_pressed = ui.input(|i| i.modifiers.shift);
            let original_aspect = if preset.height > 0 { preset.width as f32 / preset.height as f32 } else { 16.0 / 9.0 };
            let lock_aspect = if shift_pressed { original_aspect } else { 0.0 };

            changed = true;

            match active_handle {
                SelectionDragHandle::Center => {
                    rect = rect.translate(delta);
                }
                SelectionDragHandle::Right => {
                    let new_w = (rect.width() + delta.x).max(min_size.x);
                    if lock_aspect > 0.0 {
                        let new_h = new_w / lock_aspect;
                        rect.max.x = rect.min.x + new_w;
                        rect.max.y = rect.min.y + new_h;
                    } else {
                        rect.max.x = rect.min.x + new_w;
                    }
                }
                SelectionDragHandle::Left => {
                    let new_w = (rect.width() - delta.x).max(min_size.x);
                    if lock_aspect > 0.0 {
                        let new_h = new_w / lock_aspect;
                        rect.min.x = rect.max.x - new_w;
                        rect.min.y = rect.max.y - new_h;
                    } else {
                        rect.min.x = rect.max.x - new_w;
                    }
                }
                SelectionDragHandle::Bottom => {
                    let new_h = (rect.height() + delta.y).max(min_size.y);
                    if lock_aspect > 0.0 {
                        let new_w = new_h * lock_aspect;
                        rect.max.x = rect.min.x + new_w;
                        rect.max.y = rect.min.y + new_h;
                    } else {
                        rect.max.y = rect.min.y + new_h;
                    }
                }
                SelectionDragHandle::Top => {
                    let new_h = (rect.height() - delta.y).max(min_size.y);
                    if lock_aspect > 0.0 {
                        let new_w = new_h * lock_aspect;
                        rect.min.x = rect.max.x - new_w;
                        rect.min.y = rect.max.y - new_h;
                    } else {
                        rect.min.y = rect.max.y - new_h;
                    }
                }
                SelectionDragHandle::BottomRight => {
                    let new_w = (rect.width() + delta.x).max(min_size.x);
                    if lock_aspect > 0.0 {
                        let new_h = new_w / lock_aspect;
                        rect.max.x = rect.min.x + new_w;
                        rect.max.y = rect.min.y + new_h;
                    } else {
                        let new_h = (rect.height() + delta.y).max(min_size.y);
                        rect.max.x = rect.min.x + new_w;
                        rect.max.y = rect.min.y + new_h;
                    }
                }
                SelectionDragHandle::TopLeft => {
                    let new_w = (rect.width() - delta.x).max(min_size.x);
                    if lock_aspect > 0.0 {
                        let new_h = new_w / lock_aspect;
                        rect.min.x = rect.max.x - new_w;
                        rect.min.y = rect.max.y - new_h;
                    } else {
                        let new_h = (rect.height() - delta.y).max(min_size.y);
                        rect.min.x = rect.max.x - new_w;
                        rect.min.y = rect.max.y - new_h;
                    }
                }
                SelectionDragHandle::TopRight => {
                    let new_w = (rect.width() + delta.x).max(min_size.x);
                    if lock_aspect > 0.0 {
                        let new_h = new_w / lock_aspect;
                        rect.max.x = rect.min.x + new_w;
                        rect.min.y = rect.max.y - new_h;
                    } else {
                        let new_h = (rect.height() - delta.y).max(min_size.y);
                        rect.max.x = rect.min.x + new_w;
                        rect.min.y = rect.max.y - new_h;
                    }
                }
                SelectionDragHandle::BottomLeft => {
                    let new_w = (rect.width() - delta.x).max(min_size.x);
                    if lock_aspect > 0.0 {
                        let new_h = new_w / lock_aspect;
                        rect.min.x = rect.max.x - new_w;
                        rect.max.y = rect.min.y + new_h;
                    } else {
                        let new_h = (rect.height() + delta.y).max(min_size.y);
                        rect.min.x = rect.max.x - new_w;
                        rect.max.y = rect.min.y + new_h;
                    }
                }
                SelectionDragHandle::None => {}
            }

            if rect.left() < preview_rect.left() {
                rect = rect.translate(vec2(preview_rect.left() - rect.left(), 0.0));
            }
            if rect.top() < preview_rect.top() {
                rect = rect.translate(vec2(0.0, preview_rect.top() - rect.top()));
            }
            if rect.right() > preview_rect.right() {
                rect = rect.translate(vec2(preview_rect.right() - rect.right(), 0.0));
            }
            if rect.bottom() > preview_rect.bottom() {
                rect = rect.translate(vec2(0.0, preview_rect.bottom() - rect.bottom()));
            }

            rect.min.x = rect.min.x.clamp(
                preview_rect.left(),
                preview_rect.right() - min_size.x,
            );
            rect.min.y = rect.min.y.clamp(
                preview_rect.top(),
                preview_rect.bottom() - min_size.y,
            );
            rect.max.x = rect
                .max
                .x
                .clamp(rect.min.x + min_size.x, preview_rect.right());
            rect.max.y = rect
                .max
                .y
                .clamp(rect.min.y + min_size.y, preview_rect.bottom());
        }

        if ui.input(|i| i.pointer.any_released()) {
            active_handle = SelectionDragHandle::None;
            ui.data_mut(|d| d.insert_temp(drag_id, active_handle));
        }

        if response.hovered() || active_handle != SelectionDragHandle::None {
            if let Some(pointer_pos) = ui.input(|i| i.pointer.hover_pos()) {
                let dist_tl = pointer_pos.distance(rect.left_top());
                let dist_tr = pointer_pos.distance(rect.right_top());
                let dist_bl = pointer_pos.distance(rect.left_bottom());
                let dist_br = pointer_pos.distance(rect.right_bottom());

                let handle_to_use = if active_handle != SelectionDragHandle::None {
                    active_handle
                } else if dist_tl < 14.0 {
                    SelectionDragHandle::TopLeft
                } else if dist_tr < 14.0 {
                    SelectionDragHandle::TopRight
                } else if dist_bl < 14.0 {
                    SelectionDragHandle::BottomLeft
                } else if dist_br < 14.0 {
                    SelectionDragHandle::BottomRight
                } else if (pointer_pos.x - rect.left()).abs() < 10.0 && pointer_pos.y >= rect.top() && pointer_pos.y <= rect.bottom() {
                    SelectionDragHandle::Left
                } else if (pointer_pos.x - rect.right()).abs() < 10.0 && pointer_pos.y >= rect.top() && pointer_pos.y <= rect.bottom() {
                    SelectionDragHandle::Right
                } else if (pointer_pos.y - rect.top()).abs() < 10.0 && pointer_pos.x >= rect.left() && pointer_pos.x <= rect.right() {
                    SelectionDragHandle::Top
                } else if (pointer_pos.y - rect.bottom()).abs() < 10.0 && pointer_pos.x >= rect.left() && pointer_pos.x <= rect.right() {
                    SelectionDragHandle::Bottom
                } else if rect.contains(pointer_pos) {
                    SelectionDragHandle::Center
                } else {
                    SelectionDragHandle::None
                };

                match handle_to_use {
                    SelectionDragHandle::TopLeft | SelectionDragHandle::BottomRight => {
                        ui.ctx().set_cursor_icon(egui::CursorIcon::ResizeNwSe);
                    }
                    SelectionDragHandle::TopRight | SelectionDragHandle::BottomLeft => {
                        ui.ctx().set_cursor_icon(egui::CursorIcon::ResizeNeSw);
                    }
                    SelectionDragHandle::Left | SelectionDragHandle::Right => {
                        ui.ctx().set_cursor_icon(egui::CursorIcon::ResizeHorizontal);
                    }
                    SelectionDragHandle::Top | SelectionDragHandle::Bottom => {
                        ui.ctx().set_cursor_icon(egui::CursorIcon::ResizeVertical);
                    }
                    SelectionDragHandle::Center => {
                        if active_handle == SelectionDragHandle::Center {
                            ui.ctx().set_cursor_icon(egui::CursorIcon::Grabbing);
                        } else {
                            ui.ctx().set_cursor_icon(egui::CursorIcon::Grab);
                        }
                    }
                    _ => {}
                }
            }
        }

        let size_text = format!("{}x{}", preset.width, preset.height);
        ui.painter().text(
            rect.left_top() + egui::vec2(0.0, -4.0),
            egui::Align2::LEFT_BOTTOM,
            size_text,
            egui::FontId::proportional(10.0),
            Color32::from_rgb(124, 240, 164),
        );

        let bg_alpha = (preset.background_opacity.clamp(0.0, 1.0) * 255.0).round() as u8;
        let background = Color32::from_rgba_premultiplied(
            ((preset.background_color.r as u32 * bg_alpha as u32) / 255) as u8,
            ((preset.background_color.g as u32 * bg_alpha as u32) / 255) as u8,
            ((preset.background_color.b as u32 * bg_alpha as u32) / 255) as u8,
            bg_alpha,
        );
        let text_color = Color32::from_rgba_premultiplied(
            preset.text_color.r,
            preset.text_color.g,
            preset.text_color.b,
            preset.text_color.a,
        );
        let rounding = if preset.rounded_background { 12.0 } else { 0.0 };
        if bg_alpha > 0 && !preset.show_progress_bar {
            ui.painter().rect_filled(rect, rounding, background);
        }
        ui.painter().rect_stroke(
            rect,
            rounding,
            egui::Stroke::new(2.0, Color32::from_rgb(124, 240, 164)),
            egui::StrokeKind::Outside,
        );
        if preset.show_progress_bar {
            let progress_color = Color32::from_rgba_premultiplied(
                preset.progress_color.r,
                preset.progress_color.g,
                preset.progress_color.b,
                preset.progress_color.a,
            );
            
            // Draw a mock progress bar at 75% progress occupying full box size
            let bar_width = rect.width() * 0.75;
            let bar_rect = egui::Rect::from_min_max(
                egui::pos2(rect.left(), rect.top()),
                egui::pos2(rect.left() + bar_width, rect.bottom()),
            ).intersect(rect);
            
            ui.painter().rect_filled(bar_rect, 0.0, progress_color);
            
            if preset.progress_border_enabled {
                let border_color = Color32::from_rgba_premultiplied(
                    preset.progress_border_color.r,
                    preset.progress_border_color.g,
                    preset.progress_border_color.b,
                    preset.progress_border_color.a,
                );
                ui.painter().rect_stroke(
                    bar_rect,
                    0.0,
                    egui::Stroke::new(preset.progress_border_thickness, border_color),
                    egui::StrokeKind::Inside,
                );
            }
        }
        if preset.show_text {
            ui.painter().text(
                rect.center(),
                egui::Align2::CENTER_CENTER,
                "00:00.000",
                egui::FontId::proportional((preset.font_size * scale).clamp(2.0, 200.0)),
                text_color,
            );
        }

        if changed {
            preset.x = ((rect.left() - preview_rect.left()) / scale).round() as i32;
            preset.y = ((rect.top() - preview_rect.top()) / scale).round() as i32;
            preset.width = (rect.width() / scale).round().max(1.0) as i32;
            preset.height = (rect.height() / scale).round().max(1.0) as i32;
        }

        ui.label(
            RichText::new(format!(
                "X={} Y={} W={} H={}",
                preset.x, preset.y, preset.width, preset.height
            ))
            .small(),
        );
        changed
    }

    fn apply_locked_aspect_ratio(
        handle: &str,
        aspect_ratio: f32,
        bounds: egui::Rect,
        min_size: egui::Vec2,
        rect: &mut egui::Rect,
    ) {
        if aspect_ratio <= 0.0 {
            return;
        }
        match handle {
            "nw" | "ne" | "se" | "sw" => {
                let anchor = match handle {
                    "nw" => rect.right_bottom(),
                    "ne" => rect.left_bottom(),
                    "se" => rect.left_top(),
                    "sw" => rect.right_top(),
                    _ => rect.right_bottom(),
                };
                let moving = match handle {
                    "nw" => rect.left_top(),
                    "ne" => rect.right_top(),
                    "se" => rect.right_bottom(),
                    "sw" => rect.left_bottom(),
                    _ => rect.left_top(),
                };
                let mut dx = moving.x - anchor.x;
                let mut dy = moving.y - anchor.y;
                let width = dx.abs().max(min_size.x);
                let height = dy.abs().max(min_size.y);
                let expected_height = width / aspect_ratio;
                let expected_width = height * aspect_ratio;
                if expected_height >= height {
                    dy = dy.signum() * expected_height.max(min_size.y);
                } else {
                    dx = dx.signum() * expected_width.max(min_size.x);
                }
                let new_corner = egui::pos2(anchor.x + dx, anchor.y + dy);
                *rect = egui::Rect::from_two_pos(anchor, new_corner).intersect(bounds);
            }
            "n" | "s" => {
                let center_x = rect.center().x;
                let anchor_y = if handle == "n" {
                    rect.bottom()
                } else {
                    rect.top()
                };
                let moving_y = if handle == "n" {
                    rect.top()
                } else {
                    rect.bottom()
                };
                let height = (moving_y - anchor_y).abs().max(min_size.y);
                let width = (height * aspect_ratio).max(min_size.x);
                let left = (center_x - width * 0.5).clamp(bounds.left(), bounds.right() - width);
                let right = left + width;
                let top = if handle == "n" {
                    (anchor_y - height).clamp(bounds.top(), bounds.bottom() - height)
                } else {
                    anchor_y.clamp(bounds.top(), bounds.bottom() - height)
                };
                let bottom = top + height;
                *rect = egui::Rect::from_min_max(egui::pos2(left, top), egui::pos2(right, bottom));
            }
            "e" | "w" => {
                let center_y = rect.center().y;
                let anchor_x = if handle == "w" {
                    rect.right()
                } else {
                    rect.left()
                };
                let moving_x = if handle == "w" {
                    rect.left()
                } else {
                    rect.right()
                };
                let width = (moving_x - anchor_x).abs().max(min_size.x);
                let height = (width / aspect_ratio).max(min_size.y);
                let top = (center_y - height * 0.5).clamp(bounds.top(), bounds.bottom() - height);
                let bottom = top + height;
                let left = if handle == "w" {
                    (anchor_x - width).clamp(bounds.left(), bounds.right() - width)
                } else {
                    anchor_x.clamp(bounds.left(), bounds.right() - width)
                };
                let right = left + width;
                *rect = egui::Rect::from_min_max(egui::pos2(left, top), egui::pos2(right, bottom));
            }
            _ => {}
        }
    }

    fn render_macro_action_option(
        ui: &mut egui::Ui,
        language: UiLanguage,
        current: &mut MacroAction,
        candidate: MacroAction,
        live_sync: &mut bool,
    ) {
        let inner = ui.allocate_ui_with_layout(
            vec2(58.0, 42.0),
            egui::Layout::top_down(egui::Align::Center),
            |ui| {
                let label_color = if *current == candidate {
                    ui.visuals().strong_text_color()
                } else {
                    ui.visuals().text_color()
                };
                let response = ui.add_sized(
                    [34.0, 24.0],
                    Button::new(Self::macro_action_icon_text(candidate))
                        .selected(*current == candidate),
                );
                ui.label(
                    RichText::new(Self::macro_action_short_label(candidate, language))
                        .size(9.0)
                        .color(label_color),
                );
                response
            },
        );
        let response = inner.inner;
        Self::show_instant_hover_tooltip(
            ui,
            &response,
            format!(
                "{}\n{}",
                Self::macro_action_label(candidate),
                Self::macro_action_tooltip(candidate, language)
            ),
        );
        if response.clicked() {
            *current = candidate;
            *live_sync = true;
            ui.close();
        }
    }

