    fn capture_master_preset_snapshot(&self, id: u32, name: String) -> MasterPreset {
        MasterPreset {
            id,
            name,
            collapsed: true,
            macros_master_enabled: self.state.macros_master_enabled,
            window_expand_controls_enabled: self.state.window_expand_controls.enabled,
            window_presets: self
                .state
                .window_presets
                .iter()
                .map(|preset| MasterWindowPresetState {
                    id: preset.id,
                    enabled: preset.enabled,
                    animate_enabled: preset.animate_enabled,
                    restore_titlebar_enabled: preset.restore_titlebar_enabled,
                })
                .collect(),
            window_focus_presets: self
                .state
                .window_focus_presets
                .iter()
                .map(|preset| MasterWindowFocusPresetState {
                    id: preset.id,
                    enabled: preset.enabled,
                })
                .collect(),
            zoom_presets: self
                .state
                .zoom_presets
                .iter()
                .map(|preset| MasterZoomPresetState {
                    id: preset.id,
                    enabled: preset.enabled,
                })
                .collect(),
            macro_groups: self
                .state
                .macro_groups
                .iter()
                .map(|group| MasterMacroGroupState {
                    id: group.id,
                    enabled: group.enabled,
                    presets: group
                        .presets
                        .iter()
                        .map(|preset| MasterMacroPresetState {
                            id: preset.id,
                            enabled: preset.enabled,
                        })
                        .collect(),
                })
                .collect(),
        }
    }

    fn ensure_master_presets(&mut self) {
        if self.state.master_presets.is_empty() {
            let id = self.state.next_master_preset_id.max(1);
            self.state.next_master_preset_id = id + 1;
            self.state
                .master_presets
                .push(self.capture_master_preset_snapshot(id, "Default".to_owned()));
            self.state.selected_master_preset_id = Some(id);
            self.persist();
            return;
        }
        self.reconcile_master_presets();
        if self.state.selected_master_preset_id.is_none() {
            self.state.selected_master_preset_id =
                self.state.master_presets.first().map(|preset| preset.id);
        }
    }

    fn reconcile_master_presets(&mut self) {
        let window_lookup = self
            .state
            .window_presets
            .iter()
            .map(|preset| {
                (
                    preset.id,
                    MasterWindowPresetState {
                        id: preset.id,
                        enabled: preset.enabled,
                        animate_enabled: preset.animate_enabled,
                        restore_titlebar_enabled: preset.restore_titlebar_enabled,
                    },
                )
            })
            .collect::<HashMap<_, _>>();
        let focus_lookup = self
            .state
            .window_focus_presets
            .iter()
            .map(|preset| {
                (
                    preset.id,
                    MasterWindowFocusPresetState {
                        id: preset.id,
                        enabled: preset.enabled,
                    },
                )
            })
            .collect::<HashMap<_, _>>();
        let zoom_lookup = self
            .state
            .zoom_presets
            .iter()
            .map(|preset| {
                (
                    preset.id,
                    MasterZoomPresetState {
                        id: preset.id,
                        enabled: preset.enabled,
                    },
                )
            })
            .collect::<HashMap<_, _>>();
        let macro_lookup = self
            .state
            .macro_groups
            .iter()
            .map(|group| {
                (
                    group.id,
                    MasterMacroGroupState {
                        id: group.id,
                        enabled: group.enabled,
                        presets: group
                            .presets
                            .iter()
                            .map(|preset| MasterMacroPresetState {
                                id: preset.id,
                                enabled: preset.enabled,
                            })
                            .collect(),
                    },
                )
            })
            .collect::<HashMap<_, _>>();

        for preset in &mut self.state.master_presets {
            preset
                .window_presets
                .retain(|item| window_lookup.contains_key(&item.id));
            for window_preset in &self.state.window_presets {
                if !preset
                    .window_presets
                    .iter()
                    .any(|item| item.id == window_preset.id)
                    && let Some(item) = window_lookup.get(&window_preset.id)
                {
                    preset.window_presets.push(item.clone());
                }
            }
            preset.window_presets.sort_by_key(|item| {
                self.state
                    .window_presets
                    .iter()
                    .position(|preset| preset.id == item.id)
                    .unwrap_or(usize::MAX)
            });

            preset
                .window_focus_presets
                .retain(|item| focus_lookup.contains_key(&item.id));
            for focus_preset in &self.state.window_focus_presets {
                if !preset
                    .window_focus_presets
                    .iter()
                    .any(|item| item.id == focus_preset.id)
                    && let Some(item) = focus_lookup.get(&focus_preset.id)
                {
                    preset.window_focus_presets.push(item.clone());
                }
            }
            preset.window_focus_presets.sort_by_key(|item| {
                self.state
                    .window_focus_presets
                    .iter()
                    .position(|preset| preset.id == item.id)
                    .unwrap_or(usize::MAX)
            });

            preset
                .zoom_presets
                .retain(|item| zoom_lookup.contains_key(&item.id));
            for zoom_preset in &self.state.zoom_presets {
                if !preset
                    .zoom_presets
                    .iter()
                    .any(|item| item.id == zoom_preset.id)
                    && let Some(item) = zoom_lookup.get(&zoom_preset.id)
                {
                    preset.zoom_presets.push(item.clone());
                }
            }
            preset.zoom_presets.sort_by_key(|item| {
                self.state
                    .zoom_presets
                    .iter()
                    .position(|preset| preset.id == item.id)
                    .unwrap_or(usize::MAX)
            });

            preset
                .macro_groups
                .retain(|item| macro_lookup.contains_key(&item.id));
            for macro_group in &self.state.macro_groups {
                if !preset
                    .macro_groups
                    .iter()
                    .any(|item| item.id == macro_group.id)
                    && let Some(item) = macro_lookup.get(&macro_group.id)
                {
                    preset.macro_groups.push(item.clone());
                }
            }
            for group_state in &mut preset.macro_groups {
                if let Some(group) = self
                    .state
                    .macro_groups
                    .iter()
                    .find(|group| group.id == group_state.id)
                {
                    group_state
                        .presets
                        .retain(|item| group.presets.iter().any(|preset| preset.id == item.id));
                    for preset_item in &group.presets {
                        if !group_state
                            .presets
                            .iter()
                            .any(|item| item.id == preset_item.id)
                        {
                            group_state.presets.push(MasterMacroPresetState {
                                id: preset_item.id,
                                enabled: preset_item.enabled,
                            });
                        }
                    }
                    group_state.presets.sort_by_key(|item| {
                        group
                            .presets
                            .iter()
                            .position(|preset| preset.id == item.id)
                            .unwrap_or(usize::MAX)
                    });
                }
            }
            preset.macro_groups.sort_by_key(|item| {
                self.state
                    .macro_groups
                    .iter()
                    .position(|group| group.id == item.id)
                    .unwrap_or(usize::MAX)
            });
        }
    }

    fn add_master_preset_from_current(&mut self) {
        let id = self.state.next_master_preset_id.max(1);
        self.state.next_master_preset_id = id + 1;
        let preset = self.capture_master_preset_snapshot(id, format!("Mode {id}"));
        self.state.master_presets.push(preset);
        self.state.selected_master_preset_id = Some(id);
        self.persist();
        self.status = format!("Captured current hotkey setup into mode {id}.");
    }

    fn update_master_preset_from_current(&mut self, preset_id: u32) {
        let replacement = self
            .state
            .master_presets
            .iter()
            .find(|preset| preset.id == preset_id)
            .map(|preset| (preset.collapsed, preset.name.clone()));
        let Some((collapsed, name)) = replacement else {
            return;
        };
        let mut snapshot = self.capture_master_preset_snapshot(preset_id, name);
        snapshot.collapsed = collapsed;
        if let Some(existing) = self
            .state
            .master_presets
            .iter_mut()
            .find(|preset| preset.id == preset_id)
        {
            *existing = snapshot;
        }
        self.persist();
        self.status = format!("Updated mode {preset_id} from current toggles.");
    }

    fn apply_master_preset(&mut self, preset_id: u32) {
        let Some(preset) = self
            .state
            .master_presets
            .iter()
            .find(|preset| preset.id == preset_id)
            .cloned()
        else {
            return;
        };
        self.state.selected_master_preset_id = Some(preset_id);
        self.state.macros_master_enabled = preset.macros_master_enabled;
        self.state.window_expand_controls.enabled = preset.window_expand_controls_enabled;

        for item in &preset.window_presets {
            if let Some(window_preset) = self
                .state
                .window_presets
                .iter_mut()
                .find(|preset| preset.id == item.id)
            {
                window_preset.enabled = item.enabled;
                window_preset.animate_enabled = item.animate_enabled;
                window_preset.restore_titlebar_enabled = item.restore_titlebar_enabled;
            }
        }
        for item in &preset.window_focus_presets {
            if let Some(focus_preset) = self
                .state
                .window_focus_presets
                .iter_mut()
                .find(|preset| preset.id == item.id)
            {
                focus_preset.enabled = item.enabled;
            }
        }
        for item in &preset.zoom_presets {
            if let Some(zoom_preset) = self
                .state
                .zoom_presets
                .iter_mut()
                .find(|preset| preset.id == item.id)
            {
                zoom_preset.enabled = item.enabled;
            }
        }
        for group_state in &preset.macro_groups {
            if let Some(group) = self
                .state
                .macro_groups
                .iter_mut()
                .find(|group| group.id == group_state.id)
            {
                group.enabled = group_state.enabled;
                for preset_state in &group_state.presets {
                    if let Some(macro_preset) = group
                        .presets
                        .iter_mut()
                        .find(|preset| preset.id == preset_state.id)
                    {
                        macro_preset.enabled = preset_state.enabled;
                    }
                }
            }
        }
        self.sync_window_presets();
        self.sync_macro_presets();
        self.sync_macro_master_enabled();
        self.persist();
        self.status = format!("Applied mode: {}.", preset.name);
    }

    fn add_macro_group(&mut self) {
        let id = self.state.next_macro_group_id.max(1);
        self.state.next_macro_group_id = id + 1;
        let mut group = MacroGroup::new(id);
        group.name = self.unique_macro_group_name(&group.name);
        let preset_id = self.state.next_macro_preset_id.max(1);
        self.state.next_macro_preset_id = preset_id + 1;
        group.presets = vec![MacroPreset::new(preset_id)];
        self.state.macro_groups.push(group);
        self.reconcile_master_presets();
        self.sync_macro_presets();
        self.status = format!("Added macro group {id}.");
    }

    fn add_macro_preset_to_group(&mut self, group_id: u32) {
        let id = self.state.next_macro_preset_id.max(1);
        self.state.next_macro_preset_id = id + 1;
        if let Some(group) = self
            .state
            .macro_groups
            .iter_mut()
            .find(|group| group.id == group_id)
        {
            group.presets.push(MacroPreset::new(id));
            self.reconcile_master_presets();
            self.sync_macro_presets();
            self.status = format!("Added macro preset {id}.");
        }
    }

    fn open_macro_ai_dialog_for_preset(&mut self, group_id: u32, preset_id: u32) {
        self.open_macro_ai_dialog_for_preset_with_mode(
            group_id,
            preset_id,
            MacroAiMode::ReplacePreset,
        );
    }

    fn open_macro_ai_dialog_for_preset_with_mode(
        &mut self,
        group_id: u32,
        preset_id: u32,
        mode: MacroAiMode,
    ) {
        if self.macro_ai_job.is_some() {
            self.status = "AI generation is already running.".to_owned();
            return;
        }
        let Some((_group_name, _preset_name)) = self
            .state
            .macro_groups
            .iter()
            .find(|group| group.id == group_id)
            .and_then(|group| {
                group
                    .presets
                    .iter()
                    .find(|preset| preset.id == preset_id)
                    .map(|_| (group.name.clone(), format!("Preset {preset_id}")))
            })
        else {
            self.status = "Macro preset not found.".to_owned();
            return;
        };

        self.macro_ai_dialog = Some(MacroAiDialog {
            group_id,
            preset_id,
            prompt: String::new(),
            mode,
        });
        let preset_label = format!("Preset {preset_id}");
        self.macro_ai_feedback = None;
        self.status = format!("Ready to generate a macro for {preset_label}.");
    }

    fn open_crosshair_ai_dialog_for_profile(&mut self, profile_index: usize) {
        if self.crosshair_ai_job.is_some() {
            self.status = "AI generation is already running.".to_owned();
            return;
        }
        let Some(profile) = self.state.profiles.get(profile_index) else {
            self.status = "Crosshair profile not found.".to_owned();
            return;
        };

        self.crosshair_ai_dialog = Some(CrosshairAiDialog {
            profile_index,
            prompt: String::new(),
        });
        self.crosshair_ai_feedback = None;
        self.status = format!("Ready to generate a crosshair style for {}.", profile.name);
    }

    fn build_crosshair_ai_prompt(&self, profile: &ProfileRecord, user_prompt: &str) -> String {
        let current_style = serde_json::to_string_pretty(&profile.style).unwrap_or_else(|_| {
            serde_json::to_string(&profile.style).unwrap_or_else(|_| "{}".to_owned())
        });
        format!(
            "Edit the current MacroNest crosshair style for one existing profile.\n\
             \n\
             Profile name: {}\n\
             Current profile enabled: {}\n\
             Current style JSON:\n{}\n\
             \n\
             Rules:\n\
             - Return only a JSON object.\n\
             - Use only fields that exist in CrosshairStyle.\n\
             - Omit any field you do not want to change.\n\
             - Do not invent new fields or prose.\n\
             - Colors must be objects with r, g, b, a.\n\
             - If the user says center, treat it as the center of the screen, not x=0 y=0.\n\
             - For center, use the current screen midpoint for x_offset and y_offset.\n\
             - If the user asks for a visual change, keep unrelated values as they are.\n\
             - If the user asks to disable or enable the crosshair, set enabled accordingly.\n\
             - The JSON object will be treated as a patch and applied onto the current style.\n\
             \n\
             User request: {}\n",
            profile.name.trim(),
            profile.enabled,
            current_style,
            user_prompt.trim()
        )
    }

    fn start_crosshair_ai_generation(&mut self, ctx: &egui::Context) {
        let Some(dialog_snapshot) = self
            .crosshair_ai_dialog
            .as_ref()
            .map(|dialog| (dialog.profile_index, dialog.prompt.trim().to_owned()))
        else {
            return;
        };
        if self.crosshair_ai_job.is_some() {
            self.crosshair_ai_feedback = Some("AI generation is already running.".to_owned());
            self.status = "AI generation is already running.".to_owned();
            return;
        }
        let (profile_index, prompt) = dialog_snapshot;
        if prompt.is_empty() {
            self.crosshair_ai_feedback = Some("Type what crosshair you want first.".to_owned());
            self.status = "Type what crosshair you want first.".to_owned();
            return;
        }
        if self.state.groq_settings.api_key.trim().is_empty() {
            self.settings_popup_open = true;
            self.state.groq_settings.details_open = true;
            self.crosshair_ai_dialog = None;
            self.crosshair_ai_feedback =
                Some("Open Settings > API and paste your Groq API key.".to_owned());
            self.status = "Open Settings > API and paste your Groq API key.".to_owned();
            return;
        }
        let Some(profile) = self.state.profiles.get(profile_index).cloned() else {
            self.crosshair_ai_feedback = Some("Crosshair profile not found.".to_owned());
            self.status = "Crosshair profile not found.".to_owned();
            self.crosshair_ai_dialog = None;
            return;
        };

        let groq_settings = self.state.groq_settings.clone();
        let prompt_body = self.build_crosshair_ai_prompt(&profile, &prompt);
        let system_instruction = "You are a deterministic MacroNest crosshair editor. Return only JSON. Use only fields that exist in CrosshairStyle. Treat the JSON as a patch that will be applied onto the current style. Do not invent fields or prose. Colors must be objects with r, g, b, a.";
        let (tx, rx) = crossbeam_channel::bounded(1);
        let token = self.crosshair_ai_next_token.max(1);
        self.crosshair_ai_next_token = token + 1;
        self.crosshair_ai_job = Some(CrosshairAiJob {
            token,
            profile_index,
            receiver: rx,
        });
        self.crosshair_ai_feedback = Some("Generating crosshair style...".to_owned());
        self.status = format!(
            "Generating a crosshair style for {} using Groq...",
            profile.name
        );
        let thread_ctx = ctx.clone();
        std::thread::spawn(move || {
            let outcome = std::panic::catch_unwind(|| {
                ai::generate_crosshair_style_patch_groq(
                    &groq_settings,
                    &prompt_body,
                    system_instruction,
                )
                .map_err(|error| error.to_string())
            })
            .unwrap_or_else(|_| Err("AI generation panicked.".to_owned()));
            let _ = tx.send(CrosshairAiJobResult {
                token,
                profile_index,
                outcome,
            });
            thread_ctx.request_repaint();
        });
        ctx.request_repaint();
    }

    fn apply_crosshair_ai_generated_style(
        &mut self,
        profile_index: usize,
        patch: ai::CrosshairStylePatch,
    ) {
        let profile_name = {
            let Some(profile) = self.state.profiles.get_mut(profile_index) else {
                self.crosshair_ai_feedback = Some("Crosshair profile not found.".to_owned());
                self.status = "Crosshair profile not found.".to_owned();
                return;
            };
            patch.apply_to(&mut profile.style);
            if let Some(enabled) = patch.enabled {
                profile.enabled = enabled;
            }
            profile.style.enabled = profile.enabled;
            profile.name.clone()
        };
        self.state.active_style = self.state.profiles[profile_index].style.clone();
        self.sync_crosshair_profile(profile_index, &self.state.profiles[profile_index]);
        self.crosshair_editor_dirty = true;
        self.status = format!("Updated crosshair style for {}.", profile_name);
    }

    fn open_command_ai_dialog_for_preset(&mut self, preset_id: u32) {
        if self.command_ai_job.is_some() {
            self.status = "AI generation is already running.".to_owned();
            return;
        }
        let Some(preset) = self
            .state
            .command_presets
            .iter()
            .find(|preset| preset.id == preset_id)
        else {
            self.status = "Custom preset not found.".to_owned();
            return;
        };

        self.command_ai_dialog = Some(CommandAiDialog {
            preset_id,
            prompt: String::new(),
        });
        self.command_ai_feedback = None;
        self.status = format!("Ready to generate a custom command for {}.", preset.name);
    }

    fn build_custom_ai_prompt(&self, preset: &CommandPreset, user_prompt: &str) -> String {
        let current_preset = serde_json::to_string_pretty(preset)
            .unwrap_or_else(|_| serde_json::to_string(preset).unwrap_or_else(|_| "{}".to_owned()));
        let target_window = preset
            .target_window_title
            .as_deref()
            .unwrap_or("Any focused window");
        let extra_windows = if preset.extra_target_window_titles.is_empty() {
            "None".to_owned()
        } else {
            preset.extra_target_window_titles.join(", ")
        };
        let open_windows = if self.open_windows.is_empty() {
            "None".to_owned()
        } else {
            self.open_windows.join("\n- ")
        };
        format!(
            "Edit the current MacroNest custom preset for one existing preset.\n\
             \n\
             Custom preset name: {}\n\
             Target window: {}\n\
             Extra target windows: {}\n\
             Current custom preset JSON:\n{}\n\
             Available open windows:\n- {}\n\
             \n\
             Rules:\n\
             - Return only a JSON object.\n\
             - Use only fields that exist in CommandPreset.\n\
             - Omit any field you do not want to change.\n\
             - Do not invent new fields or prose.\n\
             - The command field must be a shell command or PowerShell command string, not a macro step list.\n\
             - If the user asks for a simple task like shutdown, open app, launch file, or run console commands, encode that as the command string.\n\
             - If the user says center or center of the screen, that is not screen coordinate 0,0; that means the middle of the screen.\n\
             - Keep unrelated fields unchanged.\n\
             - IMPORTANT: You MUST also generate an appropriate, concise, and descriptive name for the 'name' field (in the same language as the user request, maximum 3-5 words, e.g., 'Start MsPaint' or 'Mở Paint') that summarizes what the new command does. Do not leave the 'name' field unchanged if the command's behavior is changed.\n\
             - The JSON object will be treated as a patch and applied onto the current custom preset.\n\
             \n\
             User request: {}\n",
            preset.name.trim(),
            target_window,
            extra_windows,
            current_preset,
            open_windows,
            user_prompt.trim()
        )
    }

    fn start_custom_ai_generation(&mut self, ctx: &egui::Context) {
        let Some(dialog_snapshot) = self
            .command_ai_dialog
            .as_ref()
            .map(|dialog| (dialog.preset_id, dialog.prompt.trim().to_owned()))
        else {
            return;
        };
        if self.command_ai_job.is_some() {
            self.command_ai_feedback = Some("AI generation is already running.".to_owned());
            self.status = "AI generation is already running.".to_owned();
            return;
        }
        let (preset_id, prompt) = dialog_snapshot;
        if prompt.is_empty() {
            self.command_ai_feedback = Some("Type what custom command you want first.".to_owned());
            self.status = "Type what custom command you want first.".to_owned();
            return;
        }
        if self.state.groq_settings.api_key.trim().is_empty() {
            self.settings_popup_open = true;
            self.state.groq_settings.details_open = true;
            self.command_ai_dialog = None;
            self.command_ai_feedback =
                Some("Open Settings > API and paste your Groq API key.".to_owned());
            self.status = "Open Settings > API and paste your Groq API key.".to_owned();
            return;
        }
        let Some(preset) = self
            .state
            .command_presets
            .iter()
            .find(|preset| preset.id == preset_id)
            .cloned()
        else {
            self.command_ai_feedback = Some("Custom preset not found.".to_owned());
            self.status = "Custom preset not found.".to_owned();
            self.command_ai_dialog = None;
            return;
        };

        let groq_settings = self.state.groq_settings.clone();
        let prompt_body = self.build_custom_ai_prompt(&preset, &prompt);
        let system_instruction = "You are a deterministic MacroNest custom preset compiler. Return one JSON object only. Use only fields that exist in CommandPreset. You MUST also generate an appropriate, concise, descriptive name in the 'name' field that summarizes the command. The command field must contain a shell or PowerShell command string. Do not return markdown, arrays, or prose.";
        let (tx, rx) = crossbeam_channel::bounded(1);
        let token = self.command_ai_next_token.max(1);
        self.command_ai_next_token = token + 1;
        self.command_ai_job = Some(CommandAiJob {
            token,
            preset_id,
            receiver: rx,
        });
        self.command_ai_feedback = Some("Generating custom preset...".to_owned());
        self.status = format!(
            "Generating a custom preset for {} using Groq...",
            preset.name
        );
        let thread_ctx = ctx.clone();
        std::thread::spawn(move || {
            let outcome = std::panic::catch_unwind(|| {
                ai::generate_command_preset_patch_groq(
                    &groq_settings,
                    &prompt_body,
                    system_instruction,
                )
                .map_err(|error| error.to_string())
            })
            .unwrap_or_else(|_| Err("AI generation panicked.".to_owned()));
            let _ = tx.send(CommandAiJobResult {
                token,
                preset_id,
                outcome,
            });
            thread_ctx.request_repaint();
        });
        ctx.request_repaint();
    }

    fn apply_custom_ai_generated_patch(&mut self, preset_id: u32, patch: ai::CommandPresetPatch) {
        if preset_id == 999999 {
            if let Some(target) = self.command_ai_step_target.take() {
                let (group_id, preset_id, step_index) = target;
                let mut temp_preset = CommandPreset::new(999999);
                if let Some(group) = self
                    .state
                    .macro_groups
                    .iter()
                    .find(|group| group.id == group_id)
                {
                    if let Some(preset) = group
                        .presets
                        .iter()
                        .find(|preset| preset.id == preset_id)
                    {
                        if let Some(step_index) = step_index {
                            if let Some(step) = preset.steps.get(step_index) {
                                temp_preset.command = step.command_preset_command.clone();
                                temp_preset.use_powershell = step.command_preset_use_powershell;
                            }
                        } else {
                            temp_preset.command = preset.hold_stop_step.command_preset_command.clone();
                            temp_preset.use_powershell = preset.hold_stop_step.command_preset_use_powershell;
                        }
                    }
                }
                let old_name = temp_preset.name.clone();
                patch.apply_to(&mut temp_preset);

                // Robust Fallback: If the name wasn't renamed by AI, but the command changed, let's auto-generate a descriptive name!
                if temp_preset.name.trim().eq_ignore_ascii_case(old_name.trim()) && temp_preset.command.trim() != old_name.trim() {
                    let cmd_lower = temp_preset.command.to_ascii_lowercase();
                    let new_fallback_name = if cmd_lower.contains("shutdown") {
                        "Tắt máy".to_owned()
                    } else if cmd_lower.contains("mspaint") || cmd_lower.contains("pbrush") {
                        "Mở Paint".to_owned()
                    } else if cmd_lower.contains("calc") {
                        "Mở Máy tính".to_owned()
                    } else if cmd_lower.contains("notepad") {
                        "Mở Notepad".to_owned()
                    } else if cmd_lower.contains("discord") {
                        "Mở Discord".to_owned()
                    } else if cmd_lower.contains("chrome") {
                        "Mở Chrome".to_owned()
                    } else if cmd_lower.contains("edge") || cmd_lower.contains("msedge") {
                        "Mở Edge".to_owned()
                    } else {
                        let mut parts = temp_preset.command.split_whitespace();
                        if let Some(first) = parts.next() {
                            let name_part = first
                                .trim_end_matches(".exe")
                                .trim_end_matches(".bat")
                                .trim_end_matches(".cmd")
                                .to_owned();
                            let mut chars = name_part.chars();
                            if let Some(first_char) = chars.next() {
                                let capitalized = first_char.to_uppercase().collect::<String>() + chars.as_str();
                                format!("Mở {}", capitalized)
                            } else {
                                temp_preset.name.clone()
                            }
                        } else {
                            temp_preset.name.clone()
                        }
                    };
                    temp_preset.name = new_fallback_name;
                }

                if let Some(group) = self
                    .state
                    .macro_groups
                    .iter_mut()
                    .find(|group| group.id == group_id)
                {
                    if let Some(preset) = group
                        .presets
                        .iter_mut()
                        .find(|preset| preset.id == preset_id)
                    {
                        if let Some(step_index) = step_index {
                            if let Some(step) = preset.steps.get_mut(step_index) {
                                step.command_preset_command = temp_preset.command;
                                step.command_preset_use_powershell = temp_preset.use_powershell;
                                step.key = temp_preset.name.clone();
                            }
                        } else {
                            preset.hold_stop_step.command_preset_command = temp_preset.command;
                            preset.hold_stop_step.command_preset_use_powershell = temp_preset.use_powershell;
                            preset.hold_stop_step.key = temp_preset.name.clone();
                        }
                        self.status = "Updated step command and preset name.".to_owned();
                    }
                }
                self.persist();
                self.state.command_presets.retain(|p| p.id != 999999);
            }
            return;
        }
        let preset_name = {
            let Some(preset) = self
                .state
                .command_presets
                .iter_mut()
                .find(|preset| preset.id == preset_id)
            else {
                self.command_ai_feedback = Some("Custom preset not found.".to_owned());
                self.status = "Custom preset not found.".to_owned();
                return;
            };
            let old_name = preset.name.clone();
            patch.apply_to(preset);
            preset.collapsed = false;

            // Robust Fallback: If the name wasn't renamed by AI, but the command changed, let's auto-generate a descriptive name!
            if preset.name.trim().eq_ignore_ascii_case(old_name.trim()) && preset.command.trim() != old_name.trim() {
                let cmd_lower = preset.command.to_ascii_lowercase();
                let is_vietnamese = old_name.chars().any(|c| c as u32 > 127);
                let new_fallback_name = if cmd_lower.contains("shutdown") {
                    if is_vietnamese { "Tắt máy".to_owned() } else { "Shutdown".to_owned() }
                } else if cmd_lower.contains("mspaint") || cmd_lower.contains("pbrush") {
                    if is_vietnamese { "Mở Paint".to_owned() } else { "Start Paint".to_owned() }
                } else if cmd_lower.contains("calc") {
                    if is_vietnamese { "Mở Máy tính".to_owned() } else { "Start Calculator".to_owned() }
                } else if cmd_lower.contains("notepad") {
                    if is_vietnamese { "Mở Notepad".to_owned() } else { "Start Notepad".to_owned() }
                } else if cmd_lower.contains("discord") {
                    if is_vietnamese { "Mở Discord".to_owned() } else { "Start Discord".to_owned() }
                } else if cmd_lower.contains("chrome") {
                    if is_vietnamese { "Mở Chrome".to_owned() } else { "Start Chrome".to_owned() }
                } else if cmd_lower.contains("edge") || cmd_lower.contains("msedge") {
                    if is_vietnamese { "Mở Edge".to_owned() } else { "Start Edge".to_owned() }
                } else {
                    let mut parts = preset.command.split_whitespace();
                    if let Some(first) = parts.next() {
                        let name_part = first
                            .trim_end_matches(".exe")
                            .trim_end_matches(".bat")
                            .trim_end_matches(".cmd")
                            .to_owned();
                        let mut chars = name_part.chars();
                        if let Some(first_char) = chars.next() {
                            let capitalized = first_char.to_uppercase().collect::<String>() + chars.as_str();
                            if is_vietnamese {
                                format!("Mở {}", capitalized)
                            } else {
                                format!("Start {}", capitalized)
                            }
                        } else {
                            preset.name.clone()
                        }
                    } else {
                        preset.name.clone()
                    }
                };
                preset.name = new_fallback_name;
            }

            let new_name = preset.name.clone();
            let new_command = preset.command.clone();
            let new_use_powershell = preset.use_powershell;
            
            // Synchronize all macro steps that reference this preset
            for group in &mut self.state.macro_groups {
                for p in &mut group.presets {
                    for step in &mut p.steps {
                        if step.action == MacroAction::TriggerCommandPreset {
                            let is_match = step.key.trim() == old_name.trim()
                                || step.key.trim() == preset_id.to_string()
                                || step.key.trim() == new_name.trim();
                            if is_match {
                                step.key = preset_id.to_string();
                                step.command_preset_command = new_command.clone();
                                step.command_preset_use_powershell = new_use_powershell;
                            }
                        }
                    }
                    if p.hold_stop_step.action == MacroAction::TriggerCommandPreset {
                        let is_match = p.hold_stop_step.key.trim() == old_name.trim()
                            || p.hold_stop_step.key.trim() == preset_id.to_string()
                            || p.hold_stop_step.key.trim() == new_name.trim();
                        if is_match {
                            p.hold_stop_step.key = preset_id.to_string();
                            p.hold_stop_step.command_preset_command = new_command.clone();
                            p.hold_stop_step.command_preset_use_powershell = new_use_powershell;
                        }
                    }
                }
            }
            new_name
        };
        self.sync_command_presets();
        self.persist();
        self.status = format!("Updated custom preset {}.", preset_name);
    }

    fn poll_custom_ai_generation(&mut self, ctx: &egui::Context) {
        let Some(job) = self.command_ai_job.as_ref() else {
            return;
        };
        let job_token = job.token;
        let job_preset_id = job.preset_id;
        match job.receiver.try_recv() {
            Ok(result) => {
                self.command_ai_job = None;
                if result.token != job_token || result.preset_id != job_preset_id {
                    self.status = "AI result was ignored for a different custom preset.".to_owned();
                    ctx.request_repaint();
                    return;
                }
                match result.outcome {
                    Ok(patch) => {
                        self.apply_custom_ai_generated_patch(result.preset_id, patch);
                        if result.preset_id == 999999 {
                            self.command_ai_dialog = None;
                        }
                        self.command_ai_feedback =
                            Some("Custom preset updated successfully.".to_owned());
                        self.status = "Custom preset updated successfully.".to_owned();
                    }
                    Err(error) => {
                        let message = Self::ai_generation_feedback(&error);
                        self.command_ai_feedback = Some(message.clone());
                        self.status = message;
                    }
                }
                ctx.request_repaint();
            }
            Err(TryRecvError::Empty) => {}
            Err(TryRecvError::Disconnected) => {
                self.command_ai_job = None;
                self.command_ai_feedback = Some("AI generation stopped unexpectedly.".to_owned());
                self.status = "AI generation stopped unexpectedly.".to_owned();
                ctx.request_repaint();
            }
        }
    }

    fn poll_crosshair_ai_generation(&mut self, ctx: &egui::Context) {
        let Some(job) = self.crosshair_ai_job.as_ref() else {
            return;
        };
        let job_token = job.token;
        let job_profile_index = job.profile_index;
        match job.receiver.try_recv() {
            Ok(result) => {
                self.crosshair_ai_job = None;
                if result.token != job_token || result.profile_index != job_profile_index {
                    self.status =
                        "AI result was ignored for a different crosshair profile.".to_owned();
                    ctx.request_repaint();
                    return;
                }
                match result.outcome {
                    Ok(patch) => {
                        self.apply_crosshair_ai_generated_style(result.profile_index, patch);
                        self.crosshair_ai_feedback =
                            Some("Crosshair style updated successfully.".to_owned());
                        self.status = "Crosshair style updated successfully.".to_owned();
                    }
                    Err(error) => {
                        let message = Self::ai_generation_feedback(&error);
                        self.crosshair_ai_feedback = Some(message.clone());
                        self.status = message;
                    }
                }
                ctx.request_repaint();
            }
            Err(TryRecvError::Empty) => {}
            Err(TryRecvError::Disconnected) => {
                self.crosshair_ai_job = None;
                self.crosshair_ai_feedback = Some("AI generation stopped unexpectedly.".to_owned());
                self.status = "AI generation stopped unexpectedly.".to_owned();
                ctx.request_repaint();
            }
        }
    }

    fn build_macro_ai_prompt(
        &self,
        group: &MacroGroup,
        preset: &MacroPreset,
        user_prompt: &str,
        mode: MacroAiMode,
    ) -> String {
        let target_window = group
            .target_window_title
            .as_ref()
            .map(|value| value.as_str())
            .unwrap_or("Any focused window");
        let extra_windows = if group.extra_target_window_titles.is_empty() {
            "None".to_owned()
        } else {
            group.extra_target_window_titles.join(", ")
        };
        let current_steps = Self::format_macro_steps_for_ai_context(&preset.steps);
        let current_steps_block = if mode == MacroAiMode::ReplacePreset {
            format!("Current preset steps:\n{}", current_steps)
        } else {
            format!(
                "Current preset step count: {}.\nCurrent preset steps are immutable context only. Do not rewrite, restate, normalize, reorder, or duplicate them.\nOutput only the new step(s) to append after the existing preset.",
                preset.steps.len()
            )
        };
        let preserve_existing_steps_hint = if mode == MacroAiMode::ReplacePreset {
            "Preserve unrelated existing steps exactly. Only delete or rewrite steps the user explicitly asked to change. Never turn a tap into a hold unless the user explicitly asked for a hold."
        } else {
            "Append only the next steps after the current preset. Do not repeat, rewrite, or normalize any existing step from the preset."
        };
        let catalogs = vec![
            Self::format_id_name_catalog(
                "Current macro group presets:",
                &group
                    .presets
                    .iter()
                    .map(|preset| (preset.id, format!("Preset {}", preset.id)))
                    .collect::<Vec<_>>(),
            ),
            Self::format_id_name_catalog(
                "Available pin presets:",
                &self
                    .state
                    .pin_presets
                    .iter()
                    .map(|preset| (preset.id, preset.name.clone()))
                    .collect::<Vec<_>>(),
            ),
            Self::format_id_name_catalog(
                "Available toolbox presets:",
                &self
                    .state
                    .hud_presets
                    .iter()
                    .map(|preset| (preset.id, preset.name.clone()))
                    .collect::<Vec<_>>(),
            ),
            Self::format_custom_preset_catalog(&self.state.command_presets),
            Self::format_name_catalog(
                "Available crosshair profiles:",
                &self
                    .state
                    .profiles
                    .iter()
                    .map(|profile| profile.name.clone())
                    .collect::<Vec<_>>(),
            ),
            Self::format_id_name_catalog(
                "Available window presets:",
                &self
                    .state
                    .window_presets
                    .iter()
                    .map(|preset| (preset.id, preset.name.clone()))
                    .collect::<Vec<_>>(),
            ),
            Self::format_id_name_catalog(
                "Available focus presets:",
                &self
                    .state
                    .window_focus_presets
                    .iter()
                    .map(|preset| (preset.id, preset.name.clone()))
                    .collect::<Vec<_>>(),
            ),
            Self::format_id_name_catalog(
                "Available zoom presets:",
                &self
                    .state
                    .zoom_presets
                    .iter()
                    .map(|preset| (preset.id, preset.name.clone()))
                    .collect::<Vec<_>>(),
            ),
            Self::format_id_name_catalog(
                "Available sound presets:",
                &self
                    .state
                    .audio_settings
                    .presets
                    .iter()
                    .map(|preset| (preset.id, preset.name.clone()))
                    .collect::<Vec<_>>(),
            ),
            Self::format_id_name_catalog(
                "Available mouse sensitivity presets:",
                &self
                    .state
                    .mouse_sensitivity_presets
                    .iter()
                    .map(|preset| (preset.id, preset.name.clone()))
                    .collect::<Vec<_>>(),
            ),
            Self::format_id_name_catalog(
                "Available mouse path presets:",
                &self
                    .state
                    .mouse_path_presets
                    .iter()
                    .map(|preset| (preset.id, preset.name.clone()))
                    .collect::<Vec<_>>(),
            ),
            Self::format_id_name_catalog(
                "Available image search presets:",
                &self
                    .state
                    .vision_presets
                    .iter()
                    .map(|preset| (preset.id, preset.name.clone()))
                    .collect::<Vec<_>>(),
            ),
        ]
        .join("\n");
        let mode_label = match mode {
            MacroAiMode::ReplacePreset => "ReplacePreset",
            MacroAiMode::AppendSteps => "AppendSteps",
        };
        format!(
            "Create step data for one existing macro preset in MacroNest, and create helper custom presets when needed.\n\
             \n\
             Macro group: {}\n\
             Macro preset: {}\n\
             Generation mode: {}\n\
             Target window: {}\n\
             Extra target windows: {}\n\
             {}\n\
             {}\n\
             \n\
             User request: {}\n\
             \n\
             Rules:\n\
             - Return plain text only. Do not return JSON, markdown fences, bullets, or explanations.\n\
             - One command per line.\n\
             - Use the current preset steps as context, but never rewrite them unless the user explicitly asks.\n\
             - {}\n\
             - If generation mode is ReplacePreset, return the full updated script, but keep unrelated existing steps unless the user explicitly asks to remove or rewrite them.\n\
             - If generation mode is AppendSteps, return only the additional commands to append after the current preset. Do not include any existing step from the preset in the output.\n\
             - If generation mode is AppendSteps, return only the next commands to append after the current list.\n\
             - Use the catalogs above to resolve preset names or ids when the user names something.\n\
             - Use commands like wait_1000, press_D, hold_key_down_A, key_up_A, type_hello world, mouse_move_55_333, mouse_move_relative_10_-5, left_click, right_click, trigger_Open Edge, custom_Open Edge = start msedge, loop_start_4, loop_end, and stop_if_key_pressed_Escape.\n\
             - wait_1000 and similar delay lines are only prefixes for the next command. They do not become standalone steps.\n\
             - 1 second means 1000 ms.\n\
             - Use KeyPress-style taps for quick presses. Use hold_key_down_ and key_up_ only for real holds.\n\
             - Never invent a keyboard key like F, Esc, or Enter unless the user explicitly mentions that key or the request is clearly a text entry action.\n\
             - A request like \"press S press A\" should become two press_ lines, not hold commands.\n\
             - A request like \"type hello\" should become one type_ line.\n\
             - If the request contains multiple distinct OS tasks, split them into multiple custom_ lines instead of forcing everything into one command.\n\
             - For shell commands, opening apps, shutdown, launchers, or other OS tasks, define a custom_ line and then trigger it by name with trigger_. Do not add any keyboard key step for those actions unless the user asked for a key explicitly.\n\
             - A custom_ command value must stay on one line; if it needs a URL or argument, keep it on the same line as the launch command. Do not put the URL on a separate line.\n\
             - Enable crosshair should use enable_crosshair_ with the profile name, not a custom command.\n\
             - Crosshair on/off/toggle requests must never become custom commands.\n\
             - EnableMacroPreset, DisableMacroPreset, TriggerMacroPreset, EnablePinPreset, EnableZoomPreset, PlaySoundPreset, ShowToolbox, and related preset actions should use the matching preset name or id in the command suffix.\n\
             - LockKeys and UnlockKeys use a comma-separated list of keys in the suffix.\n\
             - LoopStart uses the count or an infinite marker, and LoopEnd closes the block.\n\
             - A request like \"repeat 4 times: press Q, wait 100 ms, press E\" should become one loop_start_4 line, one copy of the repeated body, then loop_end. Do not duplicate the body 4 times.\n\
             - If the user says \"wait 10 seconds then hold A and S for 5 seconds\", express it with wait_10000, hold_key_down_A, hold_key_down_S, wait_5000, key_up_A, key_up_S. The wait lines attach their delay to the next command.\n\
             - Example:\n\
             - User: press S press A move mouse to 55 333 right click, wait 10 seconds then hold A and S for 5 seconds\n\
             - Output:\n\
             wait_10000\n\
             press_S\n\
             press_A\n\
             mouse_move_55_333\n\
             right_click\n\
             hold_key_down_A\n\
             hold_key_down_S\n\
             wait_5000\n\
             key_up_A\n\
             key_up_S",
            group.name.trim(),
            format!("Preset {}", preset.id),
            mode_label,
            target_window,
            extra_windows,
            current_steps_block,
            preserve_existing_steps_hint,
            catalogs,
            user_prompt.trim()
        )
    }

    fn start_macro_ai_generation(&mut self, ctx: &egui::Context) {
        let Some(dialog_snapshot) = self.macro_ai_dialog.as_ref().map(|dialog| {
            (
                dialog.group_id,
                dialog.preset_id,
                dialog.prompt.trim().to_owned(),
                dialog.mode,
            )
        }) else {
            return;
        };
        if self.macro_ai_job.is_some() {
            self.macro_ai_feedback = Some("AI generation is already running.".to_owned());
            self.status = "AI generation is already running.".to_owned();
            return;
        }
        let (group_id, preset_id, prompt, mode) = dialog_snapshot;
        let replace_entire_preset = Self::macro_ai_request_wants_full_replace(&prompt);
        if prompt.is_empty() {
            self.macro_ai_feedback = Some("Type what macro you want first.".to_owned());
            self.status = "Type what macro you want first.".to_owned();
            return;
        }
        if self.state.groq_settings.api_key.trim().is_empty() {
            self.settings_popup_open = true;
            self.state.groq_settings.details_open = true;
            self.macro_ai_dialog = None;
            self.macro_ai_feedback =
                Some("Open Settings > API and paste your Groq API key.".to_owned());
            self.status = "Open Settings > API and paste your Groq API key.".to_owned();
            return;
        }

        let Some((group, preset_label)) = self
            .state
            .macro_groups
            .iter()
            .find(|group| group.id == group_id)
            .and_then(|group| {
                group
                    .presets
                    .iter()
                    .find(|preset| preset.id == preset_id)
                    .map(|_| (group.clone(), format!("Preset {preset_id}")))
            })
        else {
            self.macro_ai_feedback = Some("Macro preset not found.".to_owned());
            self.status = "Macro preset not found.".to_owned();
            self.macro_ai_dialog = None;
            return;
        };

        let groq_settings = self.state.groq_settings.clone();
        let macro_compiler_instruction = "You are a deterministic MacroNest macro compiler. Return plain text only, one command per line. Use the compact macro script format from the prompt. Never return JSON, markdown fences, bullets, or explanations. Prefer preserving unrelated existing steps unless the prompt explicitly asks to remove or rewrite them.";

        let Some(preset) = group.presets.iter().find(|preset| preset.id == preset_id) else {
            self.macro_ai_feedback = Some("Macro preset not found.".to_owned());
            self.status = "Macro preset not found.".to_owned();
            self.macro_ai_dialog = None;
            return;
        };

        let prompt_body = self.build_macro_ai_prompt(&group, preset, &prompt, mode);
        let (tx, rx) = crossbeam_channel::bounded(1);
        let token = self.macro_ai_next_token.max(1);
        self.macro_ai_next_token = token + 1;
        self.macro_ai_job = Some(MacroAiJob {
            token,
            group_id: group.id,
            preset_id,
            mode,
            replace_entire_preset,
            receiver: rx,
        });
        self.macro_ai_feedback = Some(match mode {
            MacroAiMode::ReplacePreset => "Generating revised macro steps...".to_owned(),
            MacroAiMode::AppendSteps => "Generating next macro steps...".to_owned(),
        });
        self.status = format!("Generating a macro for {preset_label} using Groq...");
        let thread_ctx = ctx.clone();
        std::thread::spawn(move || {
            let outcome = std::panic::catch_unwind(|| {
                ai::generate_macro_plan_groq(
                    &groq_settings,
                    &prompt_body,
                    macro_compiler_instruction,
                )
                .map_err(|error| error.to_string())
            })
            .unwrap_or_else(|_| Err("AI generation panicked.".to_owned()));
            let _ = tx.send(MacroAiJobResult {
                token,
                group_id: group.id,
                preset_id,
                outcome,
            });
            thread_ctx.request_repaint();
        });
        ctx.request_repaint();
    }

    fn apply_macro_ai_generated_steps(
        &mut self,
        group_id: u32,
        preset_id: u32,
        mode: MacroAiMode,
        replace_entire_preset: bool,
        mut steps: Vec<MacroStep>,
    ) {
        let Some((group_name, preset_label)) = self
            .state
            .macro_groups
            .iter()
            .find(|group| group.id == group_id)
            .and_then(|group| {
                group
                    .presets
                    .iter()
                    .find(|preset| preset.id == preset_id)
                    .map(|_| (group.name.clone(), format!("Preset {}", preset_id)))
            })
        else {
            self.status = "Macro preset not found.".to_owned();
            return;
        };
        let step_count = steps.len();
        {
            let Some(group) = self
                .state
                .macro_groups
                .iter_mut()
                .find(|group| group.id == group_id)
            else {
                self.status = "Macro group not found.".to_owned();
                return;
            };
            let Some(preset) = group
                .presets
                .iter_mut()
                .find(|preset| preset.id == preset_id)
            else {
                self.status = "Macro preset not found.".to_owned();
                return;
            };
            match mode {
                MacroAiMode::ReplacePreset => {
                    if replace_entire_preset {
                        ai::apply_steps_to_preset(preset, steps);
                    } else {
                        ai::merge_steps_into_preset(preset, steps);
                    }
                }
                MacroAiMode::AppendSteps => {
                    ai::strip_rewritten_append_prefix(&preset.steps, &mut steps);
                    preset.steps.extend(steps);
                }
            }
            preset.collapsed = false;
        }
        self.reconcile_master_presets();
        self.persist_macro_presets();
        self.status = match mode {
            MacroAiMode::ReplacePreset => format!(
                "Generated AI macro preset with {} step(s) in {} / {}.",
                step_count, group_name, preset_label
            ),
            MacroAiMode::AppendSteps => format!(
                "Appended {} AI step(s) in {} / {}.",
                step_count, group_name, preset_label
            ),
        };
    }

    fn upsert_custom_preset_from_macro_ai_patch(
        &mut self,
        patch: ai::CommandPresetPatch,
    ) -> Option<u32> {
        let name = patch
            .name
            .as_ref()
            .map(|value| value.trim().to_owned())
            .filter(|value| !value.is_empty())?;

        if let Some(existing_index) = self
            .state
            .command_presets
            .iter()
            .position(|preset| preset.name.trim().eq_ignore_ascii_case(&name))
        {
            let preset = &mut self.state.command_presets[existing_index];
            patch.apply_to(preset);
            if preset.name.trim().is_empty() {
                preset.name = name.clone();
            }
            return Some(preset.id);
        }

        let id = self.state.next_command_preset_id.max(1);
        self.state.next_command_preset_id = id + 1;
        let mut preset = CommandPreset::new(id);
        preset.name = name;
        patch.apply_to(&mut preset);
        if preset.command.trim().is_empty() {
            return None;
        }
        preset.collapsed = true;
        self.state.command_presets.push(preset);
        Some(id)
    }

    fn upsert_custom_preset_from_step_draft_values(
        &mut self,
        name: String,
        command: String,
        _use_powershell: bool,
    ) -> Option<u32> {
        let command = ai::normalize_command_text(&command);
        if name.is_empty() || command.is_empty() {
            return None;
        }
        let use_powershell = false;

        if let Some(existing_index) = self
            .state
            .command_presets
            .iter()
            .position(|preset| preset.name.trim().eq_ignore_ascii_case(&name))
        {
            let preset = &mut self.state.command_presets[existing_index];
            preset.name = name.clone();
            preset.command = command;
            preset.use_powershell = use_powershell;
            preset.collapsed = true;
            return Some(preset.id);
        }

        let id = self.state.next_command_preset_id.max(1);
        self.state.next_command_preset_id = id + 1;
        let mut preset = CommandPreset::new(id);
        preset.name = name;
        preset.command = command;
        preset.use_powershell = use_powershell;
        preset.collapsed = true;
        self.state.command_presets.push(preset);
        Some(id)
    }

    fn upsert_custom_preset_from_step_draft(&mut self, step: &MacroStep) -> Option<u32> {
        self.upsert_custom_preset_from_step_draft_values(
            step.key.trim().to_owned(),
            ai::normalize_command_text(&step.command_preset_command),
            step.command_preset_use_powershell,
        )
    }

    fn render_custom_preset_step_draft_popup(
        ui: &mut egui::Ui,
        response: &egui::Response,
        anchor_response: &egui::Response,
        step: &mut MacroStep,
        id_source: impl std::hash::Hash,
        step_index: Option<usize>,
        language: UiLanguage,
        command_presets: &[CommandPreset],
    ) -> (
        bool,
        Option<(Option<usize>, String, String, bool)>,
        Option<(Option<usize>, String, String, bool, bool)>,
        Option<u32>,
    ) {
        let mut changed = false;
        let mut save_request = None;
        let mut save_and_open_ai_request = None;
        let mut open_ai_preset_id = None;
        if step.action != MacroAction::TriggerCommandPreset {
            return (false, None, None, None);
        }

        let popup_id = ui.make_persistent_id((id_source, "custom-preset-draft-popup"));
        let pointer_pos = ui.input(|input| input.pointer.hover_pos());
        let mut open = response.hovered()
            || ui
                .ctx()
                .data(|data| data.get_temp::<bool>(popup_id))
                .unwrap_or(false);

        let resolved_preset = command_presets
            .iter()
            .find(|preset| {
                let key = step.key.trim();
                if key.is_empty() {
                    return false;
                }
                preset.id.to_string() == key || preset.name.trim().eq_ignore_ascii_case(key)
            })
            .cloned();

        if step.command_preset_command.trim().is_empty() {
            if let Some(preset) = resolved_preset.as_ref() {
                step.command_preset_command = preset.command.clone();
            }
        }
        if step.command_preset_use_powershell {
            step.command_preset_use_powershell = false;
            changed = true;
        }
        let is_saved_custom_preset = resolved_preset.as_ref().is_some_and(|preset| {
            preset.command.trim() == step.command_preset_command.trim()
                && !step.command_preset_command.trim().is_empty()
                && !preset.use_powershell
        });

        if open {
            let popup_size = vec2(300.0, 132.0);
            let mut pos = anchor_response.rect.left_top() - vec2(popup_size.x + 8.0, 0.0);
            let screen_rect = ui.ctx().content_rect();
            if pos.x < screen_rect.left() {
                pos.x = anchor_response.rect.right() + 8.0;
            }
            let area = egui::Area::new(popup_id)
                .order(egui::Order::Foreground)
                .fixed_pos(pos)
                .interactable(true);
            let area_response = area.show(ui.ctx(), |ui| {
                egui::Frame::popup(ui.style()).show(ui, |ui| {
                    ui.set_min_width(300.0);
                    let mut trigger_ai = false;
                    ui.horizontal(|ui| {
                        ui.label(Self::tr_lang(language, "Custom command", "Custom command"));
                        let ai_btn = egui::Button::new(Self::ai_badge_text(true))
                            .fill(Self::ai_badge_fill())
                            .stroke(Self::ai_badge_stroke());
                        if ui.add(ai_btn)
                            .on_hover_text(Self::tr_lang(language, "Generate or edit command with AI", "Tạo hoặc sửa câu lệnh bằng AI"))
                            .clicked()
                        {
                            trigger_ai = true;
                        }
                    });
                    if trigger_ai {
                        if let Some(preset) = resolved_preset.as_ref() {
                            open_ai_preset_id = Some(preset.id);
                        } else {
                            let preset_name = if step.key.trim().is_empty() {
                                "Custom Command Step".to_owned()
                            } else {
                                step.key.trim().to_owned()
                            };
                            let command_text = ai::normalize_command_text(&step.command_preset_command);
                            save_and_open_ai_request = Some((
                                step_index,
                                preset_name,
                                command_text,
                                step.command_preset_use_powershell,
                                true, // is_ad_hoc
                            ));
                        }
                    }
                    let command_changed = ui
                        .add_sized(
                            [280.0, 72.0],
                            TextEdit::multiline(&mut step.command_preset_command)
                                .desired_rows(3)
                                .hint_text("shutdown /s /t 0"),
                        )
                        .changed();
                    if command_changed {
                        changed = true;
                    }
                    if resolved_preset.is_none() {
                        ui.horizontal(|ui| {
                            ui.label(Self::tr_lang(language, "Preset name:", "Tên preset:"));
                            let name_changed = ui
                                .add(
                                    TextEdit::singleline(&mut step.key)
                                        .hint_text(Self::tr_lang(language, "Enter name...", "Nhập tên..."))
                                        .desired_width(180.0),
                                )
                                .changed();
                            if name_changed {
                                changed = true;
                            }
                        });
                        ui.add_space(2.0);
                    }
                    if !is_saved_custom_preset {
                        ui.horizontal(|ui| {
                            let save_enabled = !step.key.trim().is_empty()
                                && !ai::normalize_command_text(&step.command_preset_command)
                                    .trim()
                                    .is_empty();
                            let btn_text = if resolved_preset.is_some() {
                                Self::tr_lang(language, "Update custom preset", "Cập nhật preset")
                            } else {
                                Self::tr_lang(language, "Save as custom preset", "Lưu thành preset mới")
                            };
                            if ui
                                .add_enabled(
                                    save_enabled,
                                    egui::Button::new(btn_text),
                                )
                                .clicked()
                            {
                                let save_name = resolved_preset
                                    .as_ref()
                                    .map(|p| p.name.clone())
                                    .unwrap_or_else(|| step.key.trim().to_owned());
                                save_request = Some((
                                    step_index,
                                    save_name,
                                    ai::normalize_command_text(&step.command_preset_command),
                                    false,
                                ));
                            }
                        });
                    }
                });
            });
            let icon_pos = area_response.response.rect.right_top() + vec2(-24.0, 12.0);
            ui.painter().text(
                icon_pos,
                egui::Align2::CENTER_CENTER,
                char::from_u32(0xeb8e).unwrap_or('?').to_string(),
                egui::FontId::new(15.0, FontFamily::Name(MATERIAL_ICONS_FONT.into())),
                ui.visuals().weak_text_color(),
            );
            let popup_rect = area_response.response.rect.expand(6.0);
            let hover_popup = pointer_pos.is_some_and(|pos| popup_rect.contains(pos));
            open = response.hovered() || hover_popup;
            ui.ctx().data_mut(|data| data.insert_temp(popup_id, open));
            return (changed, save_request, save_and_open_ai_request, open_ai_preset_id);
        }

        ui.ctx().data_mut(|data| data.insert_temp(popup_id, open));
        (changed, save_request, save_and_open_ai_request, open_ai_preset_id)
    }

    fn apply_macro_ai_generated_plan(
        &mut self,
        group_id: u32,
        preset_id: u32,
        mode: MacroAiMode,
        replace_entire_preset: bool,
        mut plan: ai::MacroAiPlan,
    ) {
        ai::attach_command_preset_drafts_to_steps(&mut plan.steps, &plan.command_presets);
        ai::normalize_trigger_command_preset_keys(&mut plan.steps, &self.state.command_presets);

        self.apply_macro_ai_generated_steps(
            group_id,
            preset_id,
            mode,
            replace_entire_preset,
            plan.steps,
        );

        if !plan.command_presets.is_empty() {
            let current_status = self.status.clone();
            self.status = format!(
                "{current_status} (generated {} custom preset draft(s))",
                plan.command_presets.len()
            );
        }
    }

    fn poll_macro_ai_generation(&mut self, ctx: &egui::Context) {
        let Some(job) = self.macro_ai_job.as_ref() else {
            return;
        };
        let job_token = job.token;
        let job_group_id = job.group_id;
        let job_preset_id = job.preset_id;
        let job_mode = job.mode;
        let job_replace_entire_preset = job.replace_entire_preset;
        match job.receiver.try_recv() {
            Ok(result) => {
                self.macro_ai_job = None;
                if result.token != job_token
                    || result.group_id != job_group_id
                    || result.preset_id != job_preset_id
                {
                    self.status = "AI result was ignored for a different macro preset.".to_owned();
                    ctx.request_repaint();
                    return;
                }
                match result.outcome {
                    Ok(plan) => {
                        self.apply_macro_ai_generated_plan(
                            result.group_id,
                            result.preset_id,
                            job_mode,
                            job_replace_entire_preset,
                            plan,
                        );
                        self.macro_ai_feedback = Some(self.status.clone());
                    }
                    Err(error) => {
                        let message = Self::ai_generation_feedback(&error);
                        self.macro_ai_feedback = Some(message.clone());
                        self.status = message;
                    }
                }
                ctx.request_repaint();
            }
            Err(TryRecvError::Empty) => {}
            Err(TryRecvError::Disconnected) => {
                self.macro_ai_job = None;
                self.macro_ai_feedback = Some("AI generation stopped unexpectedly.".to_owned());
                self.status = "AI generation stopped unexpectedly.".to_owned();
                ctx.request_repaint();
            }
        }
    }

    fn add_macro_folder(&mut self) {
        let id = self.state.next_macro_folder_id.max(1);
        self.state.next_macro_folder_id = id + 1;
        self.state.macro_folders.push(MacroFolder::new(id));
        self.status = format!("Added macro folder {id}.");
    }

    fn add_macro_group_to_folder(&mut self, folder_id: u32) {
        let id = self.state.next_macro_group_id.max(1);
        self.state.next_macro_group_id = id + 1;
        let mut group = MacroGroup::new(id);
        group.name = self.unique_macro_group_name(&group.name);
        group.folder_id = Some(folder_id);
        let preset_id = self.state.next_macro_preset_id.max(1);
        self.state.next_macro_preset_id = preset_id + 1;
        group.presets = vec![MacroPreset::new(preset_id)];
        self.state.macro_groups.push(group);
        self.reconcile_master_presets();
        self.sync_macro_presets();
        self.status = format!("Added macro group {id} to folder.");
    }

    fn clone_macro_preset_with_new_id(&mut self, source: &MacroPreset) -> MacroPreset {
        let new_preset_id = self.state.next_macro_preset_id.max(1);
        self.state.next_macro_preset_id = new_preset_id + 1;
        let mut preset = source.clone();
        let old_preset_id = preset.id;
        preset.id = new_preset_id;
        preset.collapsed = true;
        Self::remap_macro_step_self_ref(&mut preset.hold_stop_step, old_preset_id, new_preset_id);
        for step in &mut preset.steps {
            Self::remap_macro_step_self_ref(step, old_preset_id, new_preset_id);
        }
        preset
    }

    fn remap_macro_step_self_ref(step: &mut MacroStep, old_preset_id: u32, new_preset_id: u32) {
        if matches!(
            step.action,
            MacroAction::TriggerMacroPreset
                | MacroAction::EnableMacroPreset
                | MacroAction::DisableMacroPreset
        ) && let Ok(id) = step.key.trim().parse::<u32>()
            && id == old_preset_id
        {
            step.key = new_preset_id.to_string();
        }
    }

    fn clone_macro_group_with_new_ids(
        &mut self,
        source_group: &MacroGroup,
        target_folder_id: Option<u32>,
    ) -> MacroGroup {
        let new_group_id = self.state.next_macro_group_id.max(1);
        self.state.next_macro_group_id = new_group_id + 1;

        let mut copied_group = source_group.clone();
        copied_group.id = new_group_id;
        copied_group.name = format!("{} Copy", copied_group.name);
        copied_group.name = self.unique_macro_group_name(&copied_group.name);
        copied_group.folder_id = target_folder_id;

        let mut preset_id_map = HashMap::new();
        for preset in &mut copied_group.presets {
            let old_id = preset.id;
            let new_preset_id = self.state.next_macro_preset_id.max(1);
            self.state.next_macro_preset_id = new_preset_id + 1;
            preset.id = new_preset_id;
            preset.collapsed = true;
            preset_id_map.insert(old_id, new_preset_id);
        }

        for preset in &mut copied_group.presets {
            Self::remap_macro_step_group_refs(&mut preset.hold_stop_step, &preset_id_map);
            for step in &mut preset.steps {
                Self::remap_macro_step_group_refs(step, &preset_id_map);
            }
        }

        copied_group
    }

    fn unique_macro_group_name(&self, base_name: &str) -> String {
        let base = base_name.trim();
        let base = if base.is_empty() { "Macro Group" } else { base };
        let lower_base = base.to_ascii_lowercase();
        let names = self
            .state
            .macro_groups
            .iter()
            .map(|group| group.name.trim().to_ascii_lowercase())
            .collect::<HashSet<_>>();
        if !names.contains(&lower_base) {
            return base.to_owned();
        }
        let mut suffix = 2u32;
        loop {
            let candidate = format!("{base} {suffix}");
            if !names.contains(&candidate.to_ascii_lowercase()) {
                return candidate;
            }
            suffix += 1;
        }
    }

    fn remap_macro_step_group_refs(step: &mut MacroStep, preset_id_map: &HashMap<u32, u32>) {
        if matches!(
            step.action,
            MacroAction::TriggerMacroPreset
                | MacroAction::EnableMacroPreset
                | MacroAction::DisableMacroPreset
        ) && let Ok(old_id) = step.key.trim().parse::<u32>()
            && let Some(new_id) = preset_id_map.get(&old_id)
        {
            step.key = new_id.to_string();
        }
    }
    


    fn set_active_macro_folder_view(&mut self, folder_id: Option<u32>) {
        self.active_macro_folder_view = folder_id;
        self.selected_macro_groups.clear();
    }

    fn copy_selected_macro_groups(&mut self) {
        let mut ids = self
            .selected_macro_groups
            .iter()
            .copied()
            .collect::<Vec<_>>();
        ids.sort_unstable();
        self.macro_group_clipboard = ids;
        self.macro_group_clipboard_is_cut = false;
        self.status = format!(
            "Copied {} macro group(s).",
            self.macro_group_clipboard.len()
        );
    }

    fn copy_selected_macro_steps_for_preset(&mut self, group_id: u32, preset_id: u32) {
        let mut selected_indices = self
            .selected_macro_steps
            .iter()
            .filter_map(|(selected_group, selected_preset, selected_index)| {
                (*selected_group == group_id && *selected_preset == preset_id)
                    .then_some(*selected_index)
            })
            .collect::<Vec<_>>();
        selected_indices.sort_unstable();
        selected_indices.dedup();

        let mut clipboard = Vec::new();
        if let Some(group) = self.state.macro_groups.iter().find(|g| g.id == group_id) {
            if let Some(preset) = group.presets.iter().find(|p| p.id == preset_id) {
                for &index in &selected_indices {
                    if let Some(step) = preset.steps.get(index) {
                        clipboard.push(step.clone());
                    }
                }
            } else {
                self.status = "Macro preset not found.".to_owned();
                return;
            }
        } else {
            self.status = "Macro group not found.".to_owned();
            return;
        }

        self.macro_step_clipboard = clipboard;
        if self.macro_step_clipboard.is_empty() {
            self.status = "No selected steps to copy.".to_owned();
        } else {
            self.status = format!("Copied {} step(s).", self.macro_step_clipboard.len());
        }
    }

    fn remove_selected_macro_steps_for_preset(&mut self, group_id: u32, preset_id: u32) {
        let mut selected_indices = self
            .selected_macro_steps
            .iter()
            .filter_map(|(selected_group, selected_preset, selected_index)| {
                (*selected_group == group_id && *selected_preset == preset_id)
                    .then_some(*selected_index)
            })
            .collect::<Vec<_>>();
        selected_indices.sort_unstable();
        selected_indices.dedup();
        selected_indices.reverse();

        if let Some(group) = self.state.macro_groups.iter_mut().find(|g| g.id == group_id) {
            if let Some(preset) = group.presets.iter_mut().find(|p| p.id == preset_id) {
                for index in selected_indices {
                    if index < preset.steps.len() {
                        preset.steps.remove(index);
                    }
                }
            }
        }
        self.selected_macro_steps.retain(|(g_id, p_id, _)| *g_id != group_id || *p_id != preset_id);
    }

    fn paste_macro_steps_after(
        &mut self,
        group_id: u32,
        preset_id: u32,
        step_index: usize,
    ) -> Option<Vec<usize>> {
        if self.macro_step_clipboard.is_empty() {
            self.status = "No steps in clipboard.".to_owned();
            return None;
        }

        let clipboard_steps = self.macro_step_clipboard.clone();
        let pasted_count = clipboard_steps.len();
        let mut final_insert_at = 0;

        let Some(group) = self.state.macro_groups.iter_mut().find(|g| g.id == group_id) else {
            self.status = "Macro group not found.".to_owned();
            return None;
        };
        let Some(preset) = group.presets.iter_mut().find(|p| p.id == preset_id) else {
            self.status = "Macro preset not found.".to_owned();
            return None;
        };
        let insert_at = (step_index + 1).min(preset.steps.len());
        final_insert_at = insert_at;
        for (offset, step) in clipboard_steps.into_iter().enumerate() {
            preset.steps.insert(insert_at + offset, step);
        }

        self.status = format!("Pasted {} step(s).", pasted_count);
        Some((final_insert_at..final_insert_at + pasted_count).collect::<Vec<_>>())
    }

    fn cut_selected_macro_groups(&mut self) {
        let mut ids = self
            .selected_macro_groups
            .iter()
            .copied()
            .collect::<Vec<_>>();
        ids.sort_unstable();
        self.macro_group_clipboard = ids;
        self.macro_group_clipboard_is_cut = true;
        self.status = format!("Cut {} macro group(s).", self.macro_group_clipboard.len());
    }

    fn paste_macro_groups_into_folder(&mut self, target_folder_id: Option<u32>) {
        if self.macro_group_clipboard.is_empty() {
            self.status = "No macro groups in clipboard.".to_owned();
            return;
        }

        let clipboard_ids = self.macro_group_clipboard.clone();
        if self.macro_group_clipboard_is_cut {
            for group_id in clipboard_ids {
                if let Some(group) = self
                    .state
                    .macro_groups
                    .iter_mut()
                    .find(|group| group.id == group_id)
                {
                    group.folder_id = target_folder_id;
                }
            }
            self.macro_group_clipboard.clear();
            self.macro_group_clipboard_is_cut = false;
            self.status = "Moved macro group selection.".to_owned();
        } else {
            let sources = clipboard_ids
                .iter()
                .filter_map(|group_id| {
                    self.state
                        .macro_groups
                        .iter()
                        .find(|group| group.id == *group_id)
                        .cloned()
                })
                .collect::<Vec<_>>();
            for source in &sources {
                let copied_group = self.clone_macro_group_with_new_ids(source, target_folder_id);
                self.state.macro_groups.push(copied_group);
            }
            self.status = format!("Pasted {} macro group copy(s).", sources.len());
        }

        self.reconcile_master_presets();
        self.sync_macro_presets();
        self.persist_macro_presets();
    }

    fn remove_selected_macro_groups(&mut self) {
        if self.selected_macro_groups.is_empty() {
            self.status = "No macro groups selected.".to_owned();
            return;
        }
        let selected = self.selected_macro_groups.clone();
        self.state
            .macro_groups
            .retain(|group| !selected.contains(&group.id));
        self.selected_macro_groups.clear();
        self.macro_group_clipboard
            .retain(|group_id| !selected.contains(group_id));
        self.reconcile_master_presets();
        self.sync_macro_presets();
        self.persist_macro_presets();
        self.status = "Removed selected macro groups.".to_owned();
    }

    fn begin_capture(&mut self, target: CaptureRequest, status: String) {
        let waits_for_mouse_release = self.capture_request_accepts_mouse(&target);
        self.capture_target = Some(target.clone());
        self.capture_ignored_keys = self.snapshot_pressed_capture_keys();
        self.capture_ignored_keys
            .extend([0x01, 0x02, 0x04, 0x05, 0x06]);
        self.capture_hotkey_combo_keys = None;
        self.capture_hotkey_combo_vks.clear();
        self.capture_suppress_next_poll = false;
        self.capture_wait_for_mouse_release = waits_for_mouse_release;
        self.capture_ignore_mouse_until_release = waits_for_mouse_release;
        self.capture_suppress_polls_remaining = 0;
        self.capture_mouse_guard_until = None;
        self.status = if self.capture_request_keeps_open(&target) {
            match self.state.ui_language {
                UiLanguage::Vietnamese => {
                    "Đang bắt trigger. Giữ rồi nhả để lưu, nhấn lại nút bắt để hủy.".to_owned()
                }
                _ => "Capturing triggers. Hold keys, then release to save. Click Capture again to cancel.".to_owned(),
            }
        } else {
            status
        };
    }

    fn capture_request_keeps_open(&self, target: &CaptureRequest) -> bool {
        match target {
            CaptureRequest::MacroPresetHotkey(_, _) => true,
            CaptureRequest::MacroPresetRecordHotkey(_, _) => true,
            CaptureRequest::CommandPresetHotkey(_) => true,
            CaptureRequest::MacroPresetReleaseWaitKey(_, _) => true,
            CaptureRequest::MacroPresetHoldStopInput(group_id, preset_id) => self
                .state
                .macro_groups
                .iter()
                .find(|group| group.id == *group_id)
                .and_then(|group| group.presets.iter().find(|preset| preset.id == *preset_id))
                .is_some_and(|preset| {
                    matches!(
                        preset.hold_stop_step.action,
                        MacroAction::LockKeys | MacroAction::UnlockKeys
                    )
                }),
            CaptureRequest::MacroStepInput {
                group_id,
                preset_id,
                step_index,
            } => self
                .state
                .macro_groups
                .iter()
                .find(|group| group.id == *group_id)
                .and_then(|group| group.presets.iter().find(|preset| preset.id == *preset_id))
                .and_then(|preset| preset.steps.get(*step_index))
                .is_some_and(|step| {
                    matches!(step.action, MacroAction::LockKeys | MacroAction::UnlockKeys)
                }),
            _ => false,
        }
    }

    fn capture_request_accepts_mouse(&self, target: &CaptureRequest) -> bool {
        let _ = target;
        false
    }

    fn cancel_capture(&mut self) {
        self.capture_target = None;
        self.capture_hotkey_combo_keys = None;
        self.capture_hotkey_combo_vks.clear();
        self.capture_suppress_next_poll = false;
        self.capture_wait_for_mouse_release = true;
        self.capture_ignore_mouse_until_release = true;
        self.capture_suppress_polls_remaining = 0;
        self.capture_mouse_guard_until = None;
        self.status = "Capture cancelled.".to_owned();
    }

    fn begin_mouse_move_absolute_capture(
        &mut self,
        ctx: &egui::Context,
        target: MouseMoveAbsoluteCaptureTarget,
    ) {
        self.mouse_move_absolute_capture_target = Some(target);
        self.mouse_move_absolute_capture_wait_for_mouse_release = true;
        let viewport = ctx.input(|input| input.viewport().clone());
        self.mouse_move_absolute_restore_inner_size = viewport
            .inner_rect
            .map(|rect| rect.size())
            .or(Some(Self::desired_window_size()));
        self.mouse_move_absolute_restore_outer_pos = viewport.outer_rect.map(|rect| rect.min);
        self.center_window_next_frame = false;
        self.enforce_square_window_frames = 0;
        self.status = Self::tr_lang(
            self.state.ui_language,
            "Click anywhere on screen to capture X/Y. Press Esc to cancel.",
            "Bấm vào bất kỳ vị trí nào trên màn hình để lấy X/Y. Nhấn Esc để hủy.",
        )
        .to_owned();
        self.show_capture_info_window(ctx);
        ctx.request_repaint_after(Duration::from_millis(33));
    }

    fn cancel_mouse_move_absolute_capture(&mut self, ctx: &egui::Context) {
        if self.mouse_move_absolute_capture_target.is_none() {
            return;
        }
        self.mouse_move_absolute_capture_target = None;
        self.mouse_move_absolute_capture_wait_for_mouse_release = false;
        self.restore_mouse_move_absolute_viewport(ctx);
        self.mouse_move_absolute_capture_raise_window = true;
        self.status = Self::tr_lang(
            self.state.ui_language,
            "Mouse position capture cancelled.",
            "Đã hủy bắt tọa độ chuột.",
        )
        .to_owned();
        ctx.send_viewport_cmd(egui::ViewportCommand::Visible(true));
        ctx.send_viewport_cmd(egui::ViewportCommand::Focus);
        ctx.send_viewport_cmd(egui::ViewportCommand::RequestUserAttention(
            egui::UserAttentionType::Informational,
        ));
        ctx.request_repaint_after(Duration::from_millis(33));
    }

    fn finish_mouse_move_absolute_capture(
        &mut self,
        ctx: &egui::Context,
        target: MouseMoveAbsoluteCaptureTarget,
        screen_x: i32,
        screen_y: i32,
    ) {
        let step_result = if let Some(group_id) = target.group_id {
            self.state
                .macro_groups
                .iter_mut()
                .find(|group| group.id == group_id)
                .and_then(|group| {
                    group
                        .presets
                        .iter_mut()
                        .find(|preset| preset.id == target.preset_id)
                })
                .and_then(|preset| preset.steps.get_mut(target.step_index))
        } else {
            None
        };

        let Some(step) = step_result else {
            self.cancel_mouse_move_absolute_capture(ctx);
            self.status = Self::tr_lang(
                self.state.ui_language,
                "Mouse position capture target was not found.",
                "Không tìm thấy step để bắt tọa độ chuột.",
            )
            .to_owned();
            return;
        };

        step.x = screen_x;
        step.y = screen_y;
        step.action = MacroAction::MouseMoveAbsolute;
        self.mouse_move_absolute_capture_target = None;
        self.mouse_move_absolute_capture_wait_for_mouse_release = false;
        self.restore_mouse_move_absolute_viewport(ctx);
        self.mouse_move_absolute_capture_raise_window = true;
        self.status = match self.state.ui_language {
            UiLanguage::Vietnamese => {
                format!("Đã lấy tọa độ chuột {}, {}.", screen_x, screen_y)
            }
            _ => format!("Captured mouse position {}, {}.", screen_x, screen_y),
        };
        ctx.send_viewport_cmd(egui::ViewportCommand::Visible(true));
        ctx.send_viewport_cmd(egui::ViewportCommand::Focus);
        ctx.send_viewport_cmd(egui::ViewportCommand::RequestUserAttention(
            egui::UserAttentionType::Informational,
        ));
        ctx.request_repaint_after(Duration::from_millis(33));
        self.persist();
        if target.group_id.is_some() {
            self.sync_macro_presets();
        }
    }

    fn restore_mouse_move_absolute_viewport(&mut self, ctx: &egui::Context) {
        if let Some(size) = self.mouse_move_absolute_restore_inner_size.take() {
            ctx.send_viewport_cmd(egui::ViewportCommand::InnerSize(size));
        }
        if let Some(pos) = self.mouse_move_absolute_restore_outer_pos.take() {
            ctx.send_viewport_cmd(egui::ViewportCommand::OuterPosition(pos));
        }
    }

    fn capture_info_window_placement(
        ctx: &egui::Context,
        pointer: Option<egui::Pos2>,
    ) -> (egui::Pos2, egui::Vec2) {
        let (left, top, width, height) = window_list::virtual_screen_bounds();
        let ppp = ctx.pixels_per_point().max(0.5);
        let size = vec2(240.0, 288.0);
        let margin = 18.0;
        let viewport_rect = egui::Rect::from_min_max(
            pos2(left as f32 / ppp, top as f32 / ppp),
            pos2(
                (left as f32 + width as f32) / ppp,
                (top as f32 + height as f32) / ppp,
            ),
        );
        let candidates = [
            egui::Rect::from_min_size(
                viewport_rect.right_top() - vec2(size.x + margin, -margin),
                size,
            ),
            egui::Rect::from_min_size(viewport_rect.left_top() + vec2(margin, margin), size),
            egui::Rect::from_min_size(
                viewport_rect.right_bottom() - vec2(size.x + margin, size.y + margin),
                size,
            ),
            egui::Rect::from_min_size(
                viewport_rect.left_bottom() + vec2(margin, -(size.y + margin)),
                size,
            ),
        ];
        let pos = if let Some(pointer) = pointer {
            let pointer_safe_zone = egui::Rect::from_center_size(pointer, vec2(320.0, 320.0));
            candidates
                .into_iter()
                .find(|candidate| !candidate.intersects(pointer_safe_zone))
                .unwrap_or_else(|| {
                    candidates
                        .into_iter()
                        .max_by(|a, b| {
                            let a_dist = a.center().distance_sq(pointer);
                            let b_dist = b.center().distance_sq(pointer);
                            a_dist
                                .partial_cmp(&b_dist)
                                .unwrap_or(std::cmp::Ordering::Equal)
                        })
                        .unwrap_or(candidates[0])
                })
                .min
        } else {
            candidates[0].min
        };
        (pos, size)
    }

    fn refresh_capture_info_window(&mut self, ctx: &egui::Context) {
        let pointer = Self::current_screen_cursor_pos().map(|(x, y)| {
            let ppp = ctx.pixels_per_point().max(0.5);
            egui::pos2(x as f32 / ppp, y as f32 / ppp)
        });
        let (pos, size) = Self::capture_info_window_placement(ctx, pointer);
        ctx.send_viewport_cmd(egui::ViewportCommand::OuterPosition(pos));
        ctx.send_viewport_cmd(egui::ViewportCommand::InnerSize(size));
    }

    fn show_capture_info_window(&mut self, ctx: &egui::Context) {
        self.refresh_capture_info_window(ctx);
        ctx.send_viewport_cmd(egui::ViewportCommand::Visible(true));
        ctx.send_viewport_cmd(egui::ViewportCommand::Minimized(false));
        ctx.send_viewport_cmd(egui::ViewportCommand::Focus);
    }

    #[cfg(windows)]
    fn poll_mouse_move_absolute_capture(&mut self, ctx: &egui::Context) {
        let Some(target) = self.mouse_move_absolute_capture_target else {
            return;
        };
        ctx.request_repaint_after(Duration::from_millis(16));
        if Self::is_vk_down(0x1B) {
            self.cancel_mouse_move_absolute_capture(ctx);
            return;
        }
        if self.mouse_move_absolute_capture_wait_for_mouse_release {
            if Self::is_vk_down(0x01) {
                return;
            }
            self.mouse_move_absolute_capture_wait_for_mouse_release = false;
            ctx.request_repaint();
            return;
        }
        if !Self::is_vk_down(0x01) {
            return;
        }
        let mut point = POINT::default();
        if unsafe { GetCursorPos(&mut point) }.is_ok() {
            self.finish_mouse_move_absolute_capture(ctx, target, point.x, point.y);
        }
    }

    #[cfg(not(windows))]
    fn poll_mouse_move_absolute_capture(&mut self, _ctx: &egui::Context) {}

    fn pick_point_button_text(language: UiLanguage, active: bool) -> RichText {
        if active {
            RichText::new(Self::tr_lang(language, "Picking...", "Đang chọn..."))
                .strong()
                .color(Color32::from_rgb(255, 232, 96))
        } else {
            RichText::new(Self::tr_lang(language, "Pick", "Pick"))
        }
    }

    fn vision_template_file_for_preset(&self, preset_id: u32) -> PathBuf {
        self.paths.vision_template_file_for(preset_id)
    }

    fn begin_image_search_capture(
        &mut self,
        ctx: &egui::Context,
        target: VisionCaptureTarget,
        mode: VisionCaptureMode,
    ) {
        if self.vision_capture_active {
            return;
        }
        self.vision_capture_target = Some(target);
        self.vision_capture_mode = Some(mode);
        let viewport = ctx.input(|input| input.viewport().clone());
        self.vision_restore_inner_size = viewport
            .inner_rect
            .map(|rect| rect.size())
            .or(Some(Self::desired_window_size()));
        self.vision_restore_outer_pos = viewport.outer_rect.map(|rect| rect.min);
        self.enforce_square_window_frames = 0;
        self.center_window_next_frame = false;
        self.vision_capture_active = true;
        self.vision_capture_anchor = None;
        self.vision_capture_current = None;
        self.vision_capture_screen_region_preview = None;
        self.status = match mode {
            VisionCaptureMode::Template => {
                "Drag on screen to pick an image template. Press Esc to cancel.".to_owned()
            }
            VisionCaptureMode::SearchRegion => {
                "Drag on screen to pick the image search area. Press Esc to cancel.".to_owned()
            }
            VisionCaptureMode::ColorSample => {
                "Click a pixel on screen to pick a target color. Press Esc to cancel.".to_owned()
            }
            VisionCaptureMode::ColorPriorityAnchor => {
                "Click a point on screen to set the color priority anchor. Press Esc to cancel."
                    .to_owned()
            }
        };
        self.set_image_search_capture_mouse_blocked(true);
        let _ = self.overlay_tx.send(OverlayCommand::SetUiVisible(false));
        crate::overlay::wake_command_queue();
        self.show_capture_info_window(ctx);
        ctx.request_repaint();
    }

    fn handle_image_search_capture_mouse_down(
        &mut self,
        ctx: &egui::Context,
        screen_x: i32,
        screen_y: i32,
    ) {
        if !self.vision_capture_active {
            return;
        }
        match self
            .vision_capture_mode
            .unwrap_or(VisionCaptureMode::Template)
        {
            VisionCaptureMode::ColorSample | VisionCaptureMode::ColorPriorityAnchor => {
                // Do nothing on mouse down, wait for mouse up to capture!
            }
            VisionCaptureMode::Template | VisionCaptureMode::SearchRegion => {
                self.vision_capture_anchor =
                    Some(egui::pos2(screen_x as f32, screen_y as f32));
                self.vision_capture_current =
                    Some(egui::pos2(screen_x as f32, screen_y as f32));
                self.vision_capture_screen_region_preview = Some((screen_x, screen_y, 1, 1));
                self.status = match self
                    .vision_capture_mode
                    .unwrap_or(VisionCaptureMode::Template)
                {
                    VisionCaptureMode::Template => {
                        format!("Selecting template at {screen_x}, {screen_y}.")
                    }
                    VisionCaptureMode::SearchRegion => {
                        format!("Selecting area at {screen_x}, {screen_y}.")
                    }
                    _ => unreachable!(),
                };
                ctx.request_repaint();
            }
        }
    }

    fn handle_image_search_capture_mouse_move(
        &mut self,
        ctx: &egui::Context,
        screen_x: i32,
        screen_y: i32,
    ) {
        if !self.vision_capture_active {
            return;
        }
        match self
            .vision_capture_mode
            .unwrap_or(VisionCaptureMode::Template)
        {
            VisionCaptureMode::Template | VisionCaptureMode::SearchRegion => {
                if let Some(anchor) = self.vision_capture_anchor {
                    self.vision_capture_current =
                        Some(egui::pos2(screen_x as f32, screen_y as f32));
                    let start_x = anchor.x.round() as i32;
                    let start_y = anchor.y.round() as i32;
                    let x = start_x.min(screen_x);
                    let y = start_y.min(screen_y);
                    let width = (start_x - screen_x).abs().max(1);
                    let height = (start_y - screen_y).abs().max(1);
                    self.vision_capture_screen_region_preview = Some((x, y, width, height));
                    self.status = format!("Selecting area {width}x{height} at {x}, {y}.");
                    ctx.request_repaint();
                }
            }
            VisionCaptureMode::ColorSample | VisionCaptureMode::ColorPriorityAnchor => {}
        }
    }

    fn handle_image_search_capture_mouse_up(
        &mut self,
        ctx: &egui::Context,
        screen_x: i32,
        screen_y: i32,
    ) {
        if !self.vision_capture_active {
            return;
        }
        match self
            .vision_capture_mode
            .unwrap_or(VisionCaptureMode::Template)
        {
            VisionCaptureMode::Template | VisionCaptureMode::SearchRegion => {
                let Some(anchor) = self.vision_capture_anchor else {
                    self.cancel_image_search_capture(ctx);
                    return;
                };
                let start_x = anchor.x.round() as i32;
                let start_y = anchor.y.round() as i32;
                let x = start_x.min(screen_x);
                let y = start_y.min(screen_y);
                let width = (start_x - screen_x).abs();
                let height = (start_y - screen_y).abs();
                if width >= 2 && height >= 2 {
                    let Some(target) = self.vision_capture_target else {
                        self.cancel_image_search_capture(ctx);
                        self.status = "No image search preset is active.".to_owned();
                        return;
                    };
                    let VisionCaptureTarget::Preset(preset_id) = target;
                    let template_mode = matches!(
                        self.vision_capture_mode,
                        Some(VisionCaptureMode::Template)
                    );
                    self.finish_image_search_region_capture_command(
                        ctx,
                        preset_id,
                        template_mode,
                        x,
                        y,
                        width,
                        height,
                    );
                } else {
                    self.cancel_image_search_capture(ctx);
                    self.status = "Image area capture cancelled.".to_owned();
                }
            }
            VisionCaptureMode::ColorSample | VisionCaptureMode::ColorPriorityAnchor => {
                let Some(target) = self.vision_capture_target else {
                    self.cancel_image_search_capture(ctx);
                    self.status = "No image search preset is active.".to_owned();
                    return;
                };
                let VisionCaptureTarget::Preset(preset_id) = target;
                let priority_anchor = matches!(
                    self.vision_capture_mode,
                    Some(VisionCaptureMode::ColorPriorityAnchor)
                );
                self.finish_image_search_point_capture_command_from_screen(
                    ctx,
                    preset_id,
                    priority_anchor,
                    screen_x,
                    screen_y,
                );
            }
        }
    }

    fn spawn_image_search_point_capture(
        ui_tx: Sender<UiCommand>,
        ctx: egui::Context,
        target: VisionCaptureTarget,
        priority_anchor: bool,
    ) {
        let VisionCaptureTarget::Preset(preset_id) = target;
        Self::spawn_image_search_point_capture_thread(
            ui_tx,
            ctx,
            preset_id,
            priority_anchor,
        );
    }

    #[cfg(windows)]
    fn spawn_image_search_point_capture_thread(
        ui_tx: Sender<UiCommand>,
        ctx: egui::Context,
        preset_id: u32,
        priority_anchor: bool,
    ) {
        std::thread::spawn(move || {
            let is_down = |vk: i32| unsafe { (GetAsyncKeyState(vk) as u16 & 0x8000) != 0 };
            while is_down(0x01) {
                if is_down(0x1B) {
                    let _ = ui_tx.send(UiCommand::VisionPointCaptureCancelled(
                        "Image point capture cancelled.".to_owned(),
                    ));
                    ctx.request_repaint();
                    return;
                }
                std::thread::sleep(Duration::from_millis(6));
            }
            loop {
                if is_down(0x1B) {
                    let _ = ui_tx.send(UiCommand::VisionPointCaptureCancelled(
                        "Image point capture cancelled.".to_owned(),
                    ));
                    break;
                }
                if is_down(0x01) {
                    let mut point = POINT::default();
                    let got_point = unsafe { GetCursorPos(&mut point).is_ok() };
                    if got_point {
                        let color = if priority_anchor {
                            None
                        } else {
                            window_list::capture_virtual_screen_region(point.x, point.y, 1, 1)
                                .and_then(|frame| {
                                    (frame.rgba.len() >= 4).then(|| RgbaColor {
                                        r: frame.rgba[0],
                                        g: frame.rgba[1],
                                        b: frame.rgba[2],
                                        a: 255,
                                    })
                                })
                        };
                        let _ = ui_tx.send(UiCommand::VisionPointCaptured {
                            preset_id,
                            priority_anchor,
                            screen_x: point.x,
                            screen_y: point.y,
                            color,
                        });
                    } else {
                        let _ = ui_tx.send(UiCommand::VisionPointCaptureCancelled(
                            "Failed to read the selected screen point.".to_owned(),
                        ));
                    }
                    break;
                }
                std::thread::sleep(Duration::from_millis(6));
            }
            ctx.request_repaint();
        });
    }

    #[cfg(not(windows))]
    fn spawn_image_search_point_capture_thread(
        ui_tx: Sender<UiCommand>,
        ctx: egui::Context,
        _preset_id: u32,
        _priority_anchor: bool,
    ) {
        let _ = ui_tx.send(UiCommand::VisionPointCaptureCancelled(
            "Image point capture is only supported on Windows.".to_owned(),
        ));
        ctx.request_repaint_after(Duration::from_millis(33));
    }

    fn spawn_image_search_region_capture(
        ui_tx: Sender<UiCommand>,
        ctx: egui::Context,
        target: VisionCaptureTarget,
        template_mode: bool,
    ) {
        let VisionCaptureTarget::Preset(preset_id) = target;
        Self::spawn_image_search_region_capture_thread(
            ui_tx,
            ctx,
            preset_id,
            template_mode,
        );
    }

    #[cfg(windows)]
    fn spawn_image_search_region_capture_thread(
        ui_tx: Sender<UiCommand>,
        ctx: egui::Context,
        preset_id: u32,
        template_mode: bool,
    ) {
        std::thread::spawn(move || {
            let is_down = |vk: i32| unsafe { (GetAsyncKeyState(vk) as u16 & 0x8000) != 0 };
            let mut origin: Option<(i32, i32)> = None;
            while is_down(0x01) {
                if is_down(0x1B) {
                    let _ = ui_tx.send(UiCommand::VisionPointCaptureCancelled(
                        "Image area capture cancelled.".to_owned(),
                    ));
                    ctx.request_repaint();
                    return;
                }
                std::thread::sleep(Duration::from_millis(6));
            }
            loop {
                if is_down(0x1B) {
                    let _ = ui_tx.send(UiCommand::VisionPointCaptureCancelled(
                        "Image area capture cancelled.".to_owned(),
                    ));
                    break;
                }
                let mut point = POINT::default();
                let got_point = unsafe { GetCursorPos(&mut point).is_ok() };
                if got_point {
                    if is_down(0x01) {
                        let start = origin.get_or_insert((point.x, point.y));
                        let x = start.0.min(point.x);
                        let y = start.1.min(point.y);
                        let width = (start.0 - point.x).abs().max(1);
                        let height = (start.1 - point.y).abs().max(1);
                        let _ = ui_tx.send(UiCommand::VisionRegionPreview {
                            screen_x: x,
                            screen_y: y,
                            width,
                            height,
                        });
                        ctx.request_repaint();
                    } else if let Some(start) = origin {
                        let x = start.0.min(point.x);
                        let y = start.1.min(point.y);
                        let width = (start.0 - point.x).abs();
                        let height = (start.1 - point.y).abs();
                        if width >= 2 && height >= 2 {
                            let _ = ui_tx.send(UiCommand::VisionRegionCaptured {
                                preset_id,
                                template_mode,
                                screen_x: x,
                                screen_y: y,
                                width,
                                height,
                            });
                        } else {
                            let _ = ui_tx.send(UiCommand::VisionPointCaptureCancelled(
                                "Image area capture cancelled.".to_owned(),
                            ));
                        }
                        ctx.request_repaint();
                        break;
                    }
                }
                std::thread::sleep(Duration::from_millis(16));
            }
        });
    }

    #[cfg(not(windows))]
    fn spawn_image_search_region_capture_thread(
        ui_tx: Sender<UiCommand>,
        ctx: egui::Context,
        _preset_id: u32,
        _template_mode: bool,
    ) {
        let _ = ui_tx.send(UiCommand::VisionPointCaptureCancelled(
            "Image area capture is only supported on Windows.".to_owned(),
        ));
        ctx.request_repaint();
    }

    fn cancel_image_search_capture(&mut self, ctx: &egui::Context) {
        if !self.vision_capture_active {
            return;
        }
        let mode = self
            .vision_capture_mode
            .unwrap_or(VisionCaptureMode::Template);
        self.clear_image_search_capture_state();
        self.restore_image_search_viewport(ctx);
        self.status = match mode {
            VisionCaptureMode::Template => "Image template capture cancelled.".to_owned(),
            VisionCaptureMode::SearchRegion => {
                "Image search area capture cancelled.".to_owned()
            }
            VisionCaptureMode::ColorSample => "Image color pick cancelled.".to_owned(),
            VisionCaptureMode::ColorPriorityAnchor => {
                "Image priority point capture cancelled.".to_owned()
            }
        };
        ctx.request_repaint();
    }

    fn vision_capture_target_name(&self, target: VisionCaptureTarget) -> Option<String> {
        match target {
            VisionCaptureTarget::Preset(preset_id) => self
                .state
                .vision_presets
                .iter()
                .find(|preset| preset.id == preset_id)
                .map(|preset| preset.name.clone()),
        }
    }

    fn vision_capture_target_is_circle(&self, target: VisionCaptureTarget) -> bool {
        match target {
            VisionCaptureTarget::Preset(preset_id) => self
                .state
                .vision_presets
                .iter()
                .find(|preset| preset.id == preset_id)
                .is_some_and(|preset| preset.search_region_is_circle),
        }
    }

    fn restore_image_search_viewport(&mut self, ctx: &egui::Context) {
        if let Some(size) = self.vision_restore_inner_size.take() {
            ctx.send_viewport_cmd(egui::ViewportCommand::InnerSize(size));
        }
        if let Some(pos) = self.vision_restore_outer_pos.take() {
            ctx.send_viewport_cmd(egui::ViewportCommand::OuterPosition(pos));
        }
    }

    fn finish_image_search_capture(&mut self, ctx: &egui::Context, rect: egui::Rect) {
        let Some(target) = self.vision_capture_target else {
            self.cancel_image_search_capture(ctx);
            self.status = "No image search preset is active.".to_owned();
            return;
        };
        let mode = self
            .vision_capture_mode
            .unwrap_or(VisionCaptureMode::Template);

        self.vision_capture_active = false;
        self.vision_capture_target = None;
        self.vision_capture_mode = None;
        self.vision_capture_anchor = None;
        self.vision_capture_current = None;
        self.vision_capture_screen_region_preview = None;
        match mode {
            VisionCaptureMode::Template => {
                ctx.send_viewport_cmd(egui::ViewportCommand::Visible(false));
                let _ = self.overlay_tx.send(OverlayCommand::SetUiVisible(false));
                std::thread::sleep(Duration::from_millis(70));
                let capture =
                    self.capture_screen_region_from_rect(ctx, rect, ctx.pixels_per_point());
                self.restore_image_search_viewport(ctx);
                ctx.send_viewport_cmd(egui::ViewportCommand::Visible(true));
                ctx.send_viewport_cmd(egui::ViewportCommand::Minimized(false));
                let _ = self.overlay_tx.send(OverlayCommand::SetUiVisible(true));

                let Some(capture) = capture else {
                    self.status = "Failed to capture the selected screen area.".to_owned();
                    ctx.request_repaint();
                    return;
                };

                let (status, sync_required) = match target {
                    VisionCaptureTarget::Preset(preset_id) => {
                        let template_file = self.vision_template_file_for_preset(preset_id);
                        if let Some(parent) = template_file.parent() {
                            let _ = fs::create_dir_all(parent);
                        }
                        let save_result = image::save_buffer(
                            &template_file,
                            &capture.rgba,
                            capture.width as u32,
                            capture.height as u32,
                            image::ColorType::Rgba8,
                        );

                        if let Some(preset) = self
                            .state
                            .vision_presets
                            .iter_mut()
                            .find(|preset| preset.id == preset_id)
                        {
                            preset.collapsed = false;
                            preset.last_capture_screen_x = Some(capture.screen_x);
                            preset.last_capture_screen_y = Some(capture.screen_y);
                        }
                        self.vision_preview_cache.remove(&preset_id);
                        (
                            match save_result {
                                Ok(()) => format!(
                                    "Saved template {}x{} for preset #{}.",
                                    capture.width, capture.height, preset_id
                                ),
                                Err(error) => {
                                    format!("Captured template but could not save it: {error}")
                                }
                            },
                            true,
                        )
                    }
                };
                if sync_required {
                    self.sync_vision_presets();
                    self.persist();
                }
                self.status = status;
                ctx.request_repaint();
            }
            VisionCaptureMode::SearchRegion => {
                let region = self.screen_region_from_rect(ctx, rect, ctx.pixels_per_point());
                self.restore_image_search_viewport(ctx);
                if let Some((screen_x, screen_y, width, height)) = region {
                    match target {
                        VisionCaptureTarget::Preset(preset_id) => {
                            if let Some(preset) = self
                                .state
                                .vision_presets
                                .iter_mut()
                                .find(|preset| preset.id == preset_id)
                            {
                                preset.collapsed = false;
                                preset.search_region_screen_x = Some(screen_x);
                                preset.search_region_screen_y = Some(screen_y);
                                preset.search_region_width = Some(width);
                                preset.search_region_height = Some(height);
                            }
                            self.sync_vision_presets();
                            self.persist();
                            self.status = format!(
                                "Saved search area {}x{} at {}, {} for preset #{}.",
                                width, height, screen_x, screen_y, preset_id
                            );
                        }
                    }
                } else {
                    self.status = "Failed to save the selected search area.".to_owned();
                }
                ctx.request_repaint();
            }
            VisionCaptureMode::ColorSample => {
                let center = rect.center();
                self.finish_image_search_color_pick(ctx, center);
            }
            VisionCaptureMode::ColorPriorityAnchor => {
                let center = rect.center();
                self.finish_image_search_color_priority_anchor_pick(ctx, center);
            }
        }
    }

    fn capture_screen_region_from_rect(
        &self,
        ctx: &egui::Context,
        rect: egui::Rect,
        pixels_per_point: f32,
    ) -> Option<window_list::ScreenCaptureFrame> {
        let (capture_left, capture_top, capture_width, capture_height) =
            self.screen_region_from_rect(ctx, rect, pixels_per_point)?;
        window_list::capture_virtual_screen_region(
            capture_left,
            capture_top,
            capture_width,
            capture_height,
        )
    }

    fn screen_point_from_pos(
        &self,
        ctx: &egui::Context,
        pos: egui::Pos2,
        pixels_per_point: f32,
    ) -> Option<(i32, i32)> {
        let (left, top, _width, _height) = window_list::virtual_screen_bounds();
        let scale = pixels_per_point.max(0.5);
        let viewport_origin = ctx
            .input(|input| input.viewport().inner_rect.map(|viewport| viewport.min))
            .unwrap_or_else(|| egui::pos2(left as f32 / scale, top as f32 / scale));
        Some((
            ((viewport_origin.x + pos.x) * scale).round() as i32,
            ((viewport_origin.y + pos.y) * scale).round() as i32,
        ))
    }

    fn screen_region_from_rect(
        &self,
        ctx: &egui::Context,
        rect: egui::Rect,
        pixels_per_point: f32,
    ) -> Option<(i32, i32, i32, i32)> {
        let (left, top, _width, _height) = window_list::virtual_screen_bounds();
        let min = rect.min;
        let max = rect.max;
        let scale = pixels_per_point.max(0.5);
        let viewport_origin = ctx
            .input(|input| input.viewport().inner_rect.map(|viewport| viewport.min))
            .unwrap_or_else(|| egui::pos2(left as f32 / scale, top as f32 / scale));
        let capture_left = ((viewport_origin.x + min.x) * scale).round() as i32;
        let capture_top = ((viewport_origin.y + min.y) * scale).round() as i32;
        let capture_width = ((max.x - min.x).abs() * scale).round().max(1.0) as i32;
        let capture_height = ((max.y - min.y).abs() * scale).round().max(1.0) as i32;
        Some((capture_left, capture_top, capture_width, capture_height))
    }

    fn clear_image_search_capture_state(&mut self) {
        self.vision_capture_active = false;
        self.vision_capture_target = None;
        self.vision_capture_mode = None;
        self.vision_capture_anchor = None;
        self.vision_capture_current = None;
        self.vision_capture_screen_region_preview = None;
        self.vision_color_pick_preview_color = None;
        self.set_image_search_capture_mouse_blocked(false);
    }

    fn set_image_search_capture_mouse_blocked(&self, blocked: bool) {
        let _ = self
            .overlay_tx
            .send(OverlayCommand::SetVisionCaptureMouseBlocked(blocked));
        crate::overlay::wake_command_queue();
    }

    fn restore_image_search_capture_window(&mut self, ctx: &egui::Context) {
        self.restore_image_search_viewport(ctx);
        ctx.send_viewport_cmd(egui::ViewportCommand::Visible(true));
        ctx.send_viewport_cmd(egui::ViewportCommand::Minimized(false));
        ctx.send_viewport_cmd(egui::ViewportCommand::Focus);
        let _ = self.overlay_tx.send(OverlayCommand::SetUiVisible(true));
        crate::overlay::wake_command_queue();
    }

    fn apply_image_search_color_pick(
        &mut self,
        target: VisionCaptureTarget,
        color: RgbaColor,
    ) -> String {
        match target {
            VisionCaptureTarget::Preset(preset_id) => {
                if let Some(preset) = self
                    .state
                    .vision_presets
                    .iter_mut()
                    .find(|preset| preset.id == preset_id)
                {
                    preset.collapsed = false;
                    preset.use_color_matching = true;
                    if preset.target_colors.is_empty()
                        && let Some(existing) = preset.target_color
                    {
                        preset.target_colors.push(existing);
                    }
                    preset.target_colors.push(color);
                    preset.target_color = preset.target_colors.first().copied();
                }
                self.sync_vision_presets();
                format!(
                    "Picked color #{:02X}{:02X}{:02X} for preset #{}.",
                    color.r, color.g, color.b, preset_id
                )
            }
        }
    }

    fn apply_image_search_priority_anchor(
        &mut self,
        target: VisionCaptureTarget,
        screen_x: i32,
        screen_y: i32,
    ) -> String {
        match target {
            VisionCaptureTarget::Preset(preset_id) => {
                if let Some(preset) = self
                    .state
                    .vision_presets
                    .iter_mut()
                    .find(|preset| preset.id == preset_id)
                {
                    preset.color_priority_from_anchor = true;
                    preset.color_priority_anchor_screen_x = Some(screen_x);
                    preset.color_priority_anchor_screen_y = Some(screen_y);
                    preset.collapsed = false;
                }
                self.sync_vision_presets();
                format!("Saved priority point at {screen_x}, {screen_y} for preset #{preset_id}.")
            }
        }
    }

    fn finish_image_search_point_capture_command(
        &mut self,
        ctx: &egui::Context,
        preset_id: u32,
        priority_anchor: bool,
        screen_x: i32,
        screen_y: i32,
        color: Option<RgbaColor>,
    ) {
        let target = VisionCaptureTarget::Preset(preset_id);
        self.clear_image_search_capture_state();
        self.restore_image_search_capture_window(ctx);
        self.status = if priority_anchor {
            self.apply_image_search_priority_anchor(target, screen_x, screen_y)
        } else if let Some(color) = color {
            self.apply_image_search_color_pick(target, color)
        } else {
            "Failed to sample the selected screen color.".to_owned()
        };
        self.persist();
        ctx.request_repaint();
    }

    fn finish_image_search_point_capture_command_from_screen(
        &mut self,
        ctx: &egui::Context,
        preset_id: u32,
        priority_anchor: bool,
        screen_x: i32,
        screen_y: i32,
    ) {
        self.clear_image_search_capture_state();
        ctx.send_viewport_cmd(egui::ViewportCommand::Visible(false));
        let _ = self.overlay_tx.send(OverlayCommand::SetUiVisible(false));
        std::thread::sleep(Duration::from_millis(70));
        let color = if priority_anchor {
            None
        } else {
            window_list::capture_virtual_screen_region(screen_x, screen_y, 1, 1).and_then(|f| {
                (f.rgba.len() >= 4).then(|| RgbaColor {
                    r: f.rgba[0],
                    g: f.rgba[1],
                    b: f.rgba[2],
                    a: 255,
                })
            })
        };
        self.restore_image_search_capture_window(ctx);
        ctx.send_viewport_cmd(egui::ViewportCommand::Visible(true));
        ctx.send_viewport_cmd(egui::ViewportCommand::Minimized(false));
        let _ = self.overlay_tx.send(OverlayCommand::SetUiVisible(true));

        self.finish_image_search_point_capture_command(
            ctx,
            preset_id,
            priority_anchor,
            screen_x,
            screen_y,
            color,
        );
    }

    fn finish_image_search_color_pick_from_screen(
        &mut self,
        ctx: &egui::Context,
        screen_x: i32,
        screen_y: i32,
    ) {
        let Some(target) = self.vision_capture_target else {
            self.cancel_image_search_capture(ctx);
            self.status = "No image search preset is active.".to_owned();
            return;
        };

        self.clear_image_search_capture_state();
        ctx.send_viewport_cmd(egui::ViewportCommand::Visible(false));
        let _ = self.overlay_tx.send(OverlayCommand::SetUiVisible(false));
        std::thread::sleep(Duration::from_millis(70));
        let capture = window_list::capture_virtual_screen_region(screen_x, screen_y, 1, 1);
        self.restore_image_search_capture_window(ctx);
        ctx.send_viewport_cmd(egui::ViewportCommand::Visible(true));
        ctx.send_viewport_cmd(egui::ViewportCommand::Minimized(false));
        let _ = self.overlay_tx.send(OverlayCommand::SetUiVisible(true));

        let Some(capture) = capture else {
            self.status = "Failed to sample the selected screen color.".to_owned();
            ctx.request_repaint();
            return;
        };
        if capture.rgba.len() < 4 {
            self.status = "Failed to read the selected screen color.".to_owned();
            ctx.request_repaint();
            return;
        }

        let color = RgbaColor {
            r: capture.rgba[0],
            g: capture.rgba[1],
            b: capture.rgba[2],
            a: 255,
        };
        let status = match target {
            VisionCaptureTarget::Preset(preset_id) => {
                if let Some(preset) = self
                    .state
                    .vision_presets
                    .iter_mut()
                    .find(|preset| preset.id == preset_id)
                {
                    preset.collapsed = false;
                    preset.use_color_matching = true;
                    if preset.target_colors.is_empty() {
                        if let Some(existing) = preset.target_color {
                            preset.target_colors.push(existing);
                        }
                    }
                    preset.target_colors.push(color);
                    preset.target_color = preset.target_colors.first().copied();
                }
                self.sync_vision_presets();
                format!(
                    "Picked color #{:02X}{:02X}{:02X} for preset #{}.",
                    color.r, color.g, color.b, preset_id
                )
            }
        };
        self.persist();
        self.status = status;
        ctx.request_repaint();
    }

    fn finish_image_search_color_priority_anchor_pick_from_screen(
        &mut self,
        ctx: &egui::Context,
        screen_x: i32,
        screen_y: i32,
    ) {
        let Some(target) = self.vision_capture_target else {
            self.cancel_image_search_capture(ctx);
            self.status = "No image search preset is active.".to_owned();
            return;
        };

        self.clear_image_search_capture_state();
        self.restore_image_search_capture_window(ctx);
        ctx.send_viewport_cmd(egui::ViewportCommand::Visible(true));
        ctx.send_viewport_cmd(egui::ViewportCommand::Minimized(false));
        let _ = self.overlay_tx.send(OverlayCommand::SetUiVisible(true));

        self.status = self.apply_image_search_priority_anchor(target, screen_x, screen_y);
        self.persist();
        ctx.request_repaint();
    }

    fn finish_image_search_region_capture_command(
        &mut self,
        ctx: &egui::Context,
        preset_id: u32,
        template_mode: bool,
        screen_x: i32,
        screen_y: i32,
        width: i32,
        height: i32,
    ) {
        let target = VisionCaptureTarget::Preset(preset_id);
        self.clear_image_search_capture_state();

        if template_mode {
            ctx.send_viewport_cmd(egui::ViewportCommand::Visible(false));
            let _ = self.overlay_tx.send(OverlayCommand::SetUiVisible(false));
            std::thread::sleep(Duration::from_millis(35));
            let capture =
                window_list::capture_virtual_screen_region(screen_x, screen_y, width, height);
            self.restore_image_search_capture_window(ctx);

            let Some(capture) = capture else {
                self.status = "Failed to capture the selected screen area.".to_owned();
                ctx.request_repaint();
                return;
            };

            let template_file = self.vision_template_file_for_preset(preset_id);
            if let Some(parent) = template_file.parent() {
                let _ = fs::create_dir_all(parent);
            }
            let save_result = image::save_buffer(
                &template_file,
                &capture.rgba,
                capture.width as u32,
                capture.height as u32,
                image::ColorType::Rgba8,
            );
            if let Some(preset) = self
                .state
                .vision_presets
                .iter_mut()
                .find(|preset| preset.id == preset_id)
            {
                preset.collapsed = false;
                preset.last_capture_screen_x = Some(capture.screen_x);
                preset.last_capture_screen_y = Some(capture.screen_y);
            }
            self.vision_preview_cache.remove(&preset_id);
            self.sync_vision_presets();
            self.persist();
            self.status = match save_result {
                Ok(()) => format!(
                    "Saved template {}x{} for preset #{}.",
                    capture.width, capture.height, preset_id
                ),
                Err(error) => format!("Captured template but could not save it: {error}"),
            };
            ctx.request_repaint();
            return;
        }

        self.restore_image_search_capture_window(ctx);
        match target {
            VisionCaptureTarget::Preset(preset_id) => {
                if let Some(preset) = self
                    .state
                    .vision_presets
                    .iter_mut()
                    .find(|preset| preset.id == preset_id)
                {
                    preset.collapsed = false;
                    preset.search_region_screen_x = Some(screen_x);
                    preset.search_region_screen_y = Some(screen_y);
                    preset.search_region_width = Some(width);
                    preset.search_region_height = Some(height);
                }
                self.sync_vision_presets();
                self.persist();
                self.status = format!(
                    "Saved search area {}x{} at {}, {} for preset #{}.",
                    width, height, screen_x, screen_y, preset_id
                );
            }
        }
        ctx.request_repaint();
    }

